import type { Drill } from "./types";

// Student / senior ("Postgraduate") drills, keyed by module slug — 25 per module.
// Persona: a postgraduate student (master's/PhD) — thesis and research talks,
// advisor and committee communications, reviewer responses, grants, teaching,
// and translating research for non-specialists. Merged into course.ts.
export const STUDENT_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-stu-senior-01","level":"senior","profession":"student","title":"The buried thesis update","scenario":"Your advisor asked for a progress update before your monthly meeting. The real news: your main experiment finally worked and you have a clean result. Your draft email spends two paragraphs on troubleshooting history before mentioning it.","task":"Write a 2-3 sentence update that leads with the result.","tips":["Sentence one = the headline: the experiment worked.","The troubleshooting saga is support — compress or cut it.","End with what you'll do next, in one line."],"focus":["structure","clarity"],"placeholder":"The main experiment worked — we have a clean replication of the effect."},
    {"id":"lead-stu-senior-02","level":"senior","profession":"student","title":"The extension request that circles","scenario":"You need to push your committee meeting back three weeks because a key dataset arrived late. Your draft to your advisor opens with apologies and a full recap of the data provider's delays.","task":"Write an email that puts the request and new date in the first sentence.","tips":["Lead with the ask: move the meeting, and to when.","One sentence of reason is enough — the ask is the point.","Offer concrete alternative dates so they can act immediately."],"focus":["clarity","impact"],"placeholder":"Could we move my committee meeting to the week of the 24th?"},
    {"id":"lead-stu-senior-03","level":"senior","profession":"student","title":"The lab meeting opener","scenario":"It's your turn to present at lab meeting. You have one finding that matters — the new protocol doubles yield — but your slides start with three weeks of methods before revealing it.","task":"Write the first two sentences of your presentation, leading with the finding.","tips":["State the result before the method.","Your labmates will follow the methods better once they know where they're going.","Save the full protocol walkthrough for after the headline."],"focus":["structure","impact"]},
    {"id":"lead-stu-senior-04","level":"senior","profession":"student","title":"The reviewer response that hedges first","scenario":"Reviewer 2 asked whether your results hold without the outlier subjects. You reran the analysis: they do. Your draft response opens with three sentences about how you appreciate the concern before giving the answer.","task":"Write a 2-3 sentence response that answers first, then points to the evidence.","tips":["First sentence: yes, the results hold — with the key number.","Courtesy can be brief; the answer cannot be buried.","Point to the exact revised table or section."],"focus":["clarity","precision"]},
    {"id":"lead-stu-senior-05","level":"senior","profession":"student","title":"The abstract's first sentence","scenario":"You're drafting the abstract for your first first-author paper. Your current opening spends two sentences on how important the general field is before saying what you actually found.","task":"Write an opening sentence that states your central finding or contribution.","tips":["The first sentence should carry your result, not the field's importance.","Reviewers and readers triage by the opening line.","Background earns at most one clause, not two sentences."],"focus":["structure","concision"]},
    {"id":"lead-stu-senior-06","level":"senior","profession":"student","title":"The ask hidden in the update","scenario":"You're emailing your advisor a routine update, but what you actually need is their sign-off on the conference abstract due Friday. The ask currently sits in the last line of a long email.","task":"Rewrite the opening so the sign-off request and deadline come first.","tips":["Lead with what you need and by when.","The routine update can follow — or move to a separate message.","A deadline in sentence one is hard to miss; in sentence nine it's easy to."],"focus":["clarity","impact"]},
    {"id":"lead-stu-senior-07","level":"senior","profession":"student","title":"The negative result you're dreading","scenario":"Three months of experiments failed to replicate the pilot effect. You have to tell your advisor. Your draft walks through every parameter you varied before admitting the effect isn't there.","task":"Write a 2-3 sentence message that states the negative result up front.","tips":["Lead with the conclusion: the effect doesn't replicate.","What you tried is evidence of rigor — put it second, briefly.","Propose the next decision point so the message ends forward-looking."],"focus":["clarity","impact"],"placeholder":"The pilot effect doesn't replicate — three full runs, no signal."},
    {"id":"lead-stu-senior-08","level":"senior","profession":"student","title":"The recommendation-letter request","scenario":"You need a recommendation letter from a committee member for a fellowship due in four weeks. Your draft email spends a paragraph reminiscing about their seminar before asking.","task":"Write an email that leads with the request and the deadline.","tips":["First sentence: the ask, the fellowship, the due date.","Offer to send your CV and draft materials in the same message.","Warmth is fine — after the ask, not instead of it."],"focus":["clarity","structure"],"placeholder":"Would you be willing to write me a recommendation letter for the NSERC fellowship, due March 30?"},
    {"id":"lead-stu-senior-09","level":"senior","profession":"student","title":"The poster pitch","scenario":"A senior researcher stops at your conference poster and says, 'So what's this about?' You have maybe fifteen seconds before they drift. Your instinct is to start with the literature gap.","task":"Write the 1-2 sentence opener that leads with your finding.","tips":["Give them the result first — it's the reason to stay.","The gap and methods come alive only after the punchline.","Practice it aloud; it should sound like speech, not an abstract."],"focus":["impact","concision"]},
    {"id":"lead-stu-senior-10","level":"senior","profession":"student","title":"The equipment-failure alert","scenario":"The lab's shared -80 freezer is warming and some samples may be at risk. You need to alert the lab group channel. Your draft starts with how you noticed the temperature log looked odd.","task":"Write a message that leads with the problem and what people should do now.","tips":["First line: what's failing and whose samples are at risk.","The action ('move samples to backup freezer') belongs in the opening.","How you discovered it can wait — or be omitted."],"focus":["clarity","impact"],"placeholder":"The -80 in room 214 is failing — move your samples to the backup now."},
    {"id":"lead-stu-senior-11","level":"senior","profession":"student","title":"The TA email students will skim","scenario":"You're emailing 120 students about a change: the midterm moved from Tuesday to Thursday, same room. Your draft opens with the reasons for the change before stating it.","task":"Write a 2-3 sentence email that puts the change in the first line.","tips":["Students skim — the new date must be sentence one.","Subject line should carry the change too.","Reasons are optional; the logistics are not."],"focus":["clarity","audience"]},
    {"id":"lead-stu-senior-12","level":"senior","profession":"student","title":"The recruiter reply that rambles","scenario":"An industry recruiter emailed asking if you're interested in a data science role starting after your defense. You are. Your draft opens with three sentences about your dissertation before answering.","task":"Write a reply that answers the question in the first sentence.","tips":["Lead with yes and your availability date.","Your research background is support — one tight sentence.","End with a concrete next step: a call, your CV."],"focus":["clarity","concision"]},
    {"id":"lead-stu-senior-13","level":"senior","profession":"student","title":"The committee-member invitation","scenario":"You want Professor Okafor to join your thesis committee because of her methods expertise. Your draft email describes your entire project history before making the invitation.","task":"Write an email that leads with the invitation and why her specifically.","tips":["Sentence one: the ask — join my committee.","Sentence two: the one reason she's the right fit.","State the expected commitment (meetings per year) so she can decide fast."],"focus":["clarity","structure"]},
    {"id":"lead-stu-senior-14","level":"senior","profession":"student","title":"The conference-funding request","scenario":"You need $1,800 in department travel funding to present at a conference where your paper was accepted. Your draft to the graduate chair opens with how competitive the acceptance was.","task":"Write a request that leads with the ask and the amount.","tips":["Lead with what you're requesting and the number.","The acceptance is your strongest support — sentence two.","Include the deadline for registration so urgency is clear."],"focus":["clarity","precision"],"placeholder":"I'm requesting $1,800 in travel funding to present my accepted paper at CogSci in July."},
    {"id":"lead-stu-senior-15","level":"senior","profession":"student","title":"The data-request email","scenario":"You need a specific subset of a collaborator's dataset — trials 1-40, anonymized — to run your comparison analysis. Your draft explains your whole analysis plan before saying what you need.","task":"Write an email that puts the specific data request in the first sentence.","tips":["Lead with exactly what you need, in their dataset's terms.","One sentence of purpose is enough context.","Name a date you need it by, and why."],"focus":["precision","clarity"]},
    {"id":"lead-stu-senior-16","level":"senior","profession":"student","title":"The quals-date email","scenario":"You need to propose a date for your qualifying exam and confirm your three examiners can attend. Your draft to the graduate coordinator meanders through your preparation status first.","task":"Write a 2-3 sentence email that leads with the proposed date and the confirmation you need.","tips":["Sentence one: the date and the ask to confirm.","List the three examiners so nothing bounces back.","Your prep status is not the coordinator's question."],"focus":["clarity","concision"]},
    {"id":"lead-stu-senior-17","level":"senior","profession":"student","title":"The 'should I pivot?' question","scenario":"Your side analysis is producing stronger results than your main thesis direction, and you want your advisor's call on whether to pivot. Your draft describes both projects in detail before asking.","task":"Write a message that puts the decision you need first.","tips":["Lead with the decision: pivot or stay the course?","Give the one-sentence case for each option.","Bound the ask: what you need decided, and by when."],"focus":["clarity","structure"]},
    {"id":"lead-stu-senior-18","level":"senior","profession":"student","title":"The seminar question you ask","scenario":"At a departmental seminar, you want to ask the speaker whether their model handles missing data. Your instinct is to preface with two minutes of context about your own related work.","task":"Write the question as you would say it, point first, in 1-2 sentences.","tips":["Ask the question in sentence one.","One clause of context is the maximum a room will tolerate.","Short questions make you sound sharper, not less informed."],"focus":["concision","clarity"]},
    {"id":"lead-stu-senior-19","level":"senior","profession":"student","title":"The IRB clarification","scenario":"Your study is paused until the ethics board confirms whether your consent-form change needs full re-review. Your email to the IRB coordinator buries the question under your study's background.","task":"Write an email that leads with the specific question and the study number.","tips":["Lead with the yes/no question the coordinator can answer.","Study number in sentence one saves them a lookup.","Note that recruitment is paused — it signals urgency without drama."],"focus":["clarity","precision"]},
    {"id":"lead-stu-senior-20","level":"senior","profession":"student","title":"The chapter you want to cut","scenario":"You've concluded chapter 4 of your dissertation should be dropped — the data won't support it and it's costing you months. You need your advisor's agreement. Your draft builds the case slowly across five paragraphs.","task":"Write an opening 2-3 sentences that state the proposal first.","tips":["Lead with the proposal: cut chapter 4.","Give your two strongest reasons, one sentence each.","Ask for a meeting to decide — don't try to win it all by email."],"focus":["structure","impact"],"placeholder":"I'm proposing we cut chapter 4 from the dissertation."},
    {"id":"lead-stu-senior-21","level":"senior","profession":"student","title":"The cover letter's first line","scenario":"You're writing the cover letter for your journal submission. Your draft opens with two sentences about the journal's prestige and scope before naming what your paper shows.","task":"Write an opening sentence that states what the paper demonstrates and why it fits the journal.","tips":["Editors read hundreds of these — the finding goes first.","'We show that X' beats 'We are pleased to submit.'","Fit with the journal is one clause, not a paragraph."],"focus":["structure","concision"]},
    {"id":"lead-stu-senior-22","level":"senior","profession":"student","title":"The scooped-paper message","scenario":"A paper just published in your area does part of what your thesis chapter does. It's serious but not fatal — your second study is still novel. Your message to your advisor opens with panic and the paper's full citation history.","task":"Write a 2-3 sentence message that leads with the situation and your assessment.","tips":["First sentence: what happened and how bad it actually is.","Your assessment ('study 2 is still novel') is the news they need.","Ask for a meeting to plan the response — that's the action."],"focus":["clarity","impact"],"placeholder":"A paper out this week overlaps with study 1 — but study 2 is still novel."},
    {"id":"lead-stu-senior-23","level":"senior","profession":"student","title":"The collaboration pitch","scenario":"You want to propose a small collaboration to a postdoc in another lab: their imaging pipeline on your samples, one shared paper. Your draft describes your entire research program first.","task":"Write an email that leads with the concrete proposal.","tips":["Sentence one: the specific exchange you're proposing.","What each side contributes and gets should fit in two sentences.","Suggest a 20-minute chat as the next step."],"focus":["clarity","structure"]},
    {"id":"lead-stu-senior-24","level":"senior","profession":"student","title":"The office-hours escalation","scenario":"As head TA, you've found a grading inconsistency between sections that affects about 30 exams. The professor needs to know before grades post tomorrow. Your draft explains your grading process from the beginning.","task":"Write a message that leads with the problem and the deadline.","tips":["First line: what's wrong, how many students, and the deadline.","Your proposed fix belongs in the opening, not the postscript.","The process detail can wait for the meeting."],"focus":["clarity","impact"]},
    {"id":"lead-stu-senior-25","level":"senior","profession":"student","title":"The defense-scheduling email","scenario":"You're ready to schedule your defense and need five people's availability in the same week. Your draft email opens with a long reflection on finishing the dissertation.","task":"Write an email that leads with the scheduling ask and the target window.","tips":["Lead with the ask: defense scheduling, the target month, the poll link.","Five busy people need logistics, not sentiment.","Give a response deadline so the poll doesn't drift."],"focus":["clarity","concision"],"placeholder":"I'm scheduling my defense for the week of May 12 — could you mark your availability by Friday?"}
  ],
  "start-with-the-audience": [
    {"id":"audience-stu-senior-01","level":"senior","profession":"student","title":"The dinner-table explanation","scenario":"A family member asks what your PhD is actually about. Your honest answer involves 'transcriptional regulation in stem cell differentiation,' and you've watched eyes glaze over before.","task":"Write a 2-3 sentence explanation a non-scientist would understand and find interesting.","tips":["Start from what they care about: health, the body, a question they'd ask.","Replace every technical term with what it does.","One concrete image beats three accurate abstractions."],"focus":["audience","clarity"],"placeholder":"I study how the body decides what a young cell will grow up to be —"},
    {"id":"audience-stu-senior-02","level":"senior","profession":"student","title":"The recruiter translation","scenario":"An industry recruiter asks what your dissertation research involves. Your instinct is the academic version: models, paradigms, theoretical contributions. The recruiter is listening for skills their team can use.","task":"Write a 2-3 sentence description of your research framed around transferable skills.","tips":["Translate methods into capabilities: 'I build statistical models on messy behavioral data.'","Name the scale: dataset sizes, tools, languages.","The theory matters to your committee, not to this reader."],"focus":["audience","impact"],"placeholder":"My research comes down to building models that predict —"},
    {"id":"audience-stu-senior-03","level":"senior","profession":"student","title":"The first-year tutorial","scenario":"You're TAing an intro course and a first-year asks you to explain confidence intervals — a concept you now use daily without thinking. Your first attempt came out as a definition from a graduate textbook.","task":"Write a 3-4 sentence explanation pitched at someone meeting the idea for the first time.","tips":["Start from a situation they know — a poll, a measurement.","Beat the curse of knowledge: define nothing in terms of other jargon.","Check the altitude: intuition first, precision second."],"focus":["audience","clarity"]},
    {"id":"audience-stu-senior-04","level":"senior","profession":"student","title":"The interdisciplinary committee member","scenario":"One of your committee members is from a neighboring field and doesn't know your subfield's standard paradigm. Your progress report currently assumes everyone knows what a 'go/no-go task' is.","task":"Rewrite one paragraph of your update so this committee member can follow without a glossary.","tips":["Spell out the one piece of shorthand the outsider lacks.","Anchor the method to the question it answers, not its name.","Don't dumb down the science — build the bridge to it."],"focus":["audience","clarity"]},
    {"id":"audience-stu-senior-05","level":"senior","profession":"student","title":"The lay summary for the grant","scenario":"Your fellowship application requires a lay summary readable by the foundation's non-scientist board. Your draft is your abstract with two words changed.","task":"Write a 3-4 sentence lay summary that leads with why the work matters to people.","tips":["Open with the human stake, not the research gap.","One sentence on what you'll do, in verbs a newspaper would use.","End with what changes if you succeed."],"focus":["audience","impact"],"placeholder":"One in ten older adults will develop —"},
    {"id":"audience-stu-senior-06","level":"senior","profession":"student","title":"The participant recruitment notice","scenario":"You need 60 community participants for your study. Your draft flyer describes 'a longitudinal investigation of executive function using validated cognitive batteries.' Sign-ups so far: two.","task":"Rewrite the recruitment pitch in 2-3 sentences addressed to the participant's interests.","tips":["Lead with what they do and get: time, task, compensation.","Cut every methods word — participants don't enroll in paradigms.","Make the next step one obvious action."],"focus":["audience","clarity"],"placeholder":"Play 45 minutes of computer games for science — and $25."},
    {"id":"audience-stu-senior-07","level":"senior","profession":"student","title":"Three audiences, one result","scenario":"Your new finding needs three descriptions this week: for your advisor, for your departmental newsletter, and for your parents. You've noticed you keep giving all three the advisor version.","task":"Write the one-sentence version of your finding for each of the three audiences.","tips":["Ask what each reader already knows and what they'd do with the news.","The result is constant; the frame and vocabulary change.","If two versions look alike, one audience is being ignored."],"focus":["audience","clarity"]},
    {"id":"audience-stu-senior-08","level":"senior","profession":"student","title":"The rotation student's first day","scenario":"A new rotation student joins the lab and you're their point person. Your welcome message references 'the usual pipeline,' 'the server,' and 'journal club prep' — none of which they can decode yet.","task":"Write a 3-4 sentence orientation message that assumes zero lab context.","tips":["Name the things your shorthand points to: which server, which pipeline, what prep.","Sequence it: what to do first, then next.","One good link or contact per item beats a wall of detail."],"focus":["audience","structure"]},
    {"id":"audience-stu-senior-09","level":"senior","profession":"student","title":"The journalist's phone call","scenario":"A local reporter calls about your lab's new paper and asks what you found. Whatever you say may be quoted verbatim. Your accurate-but-fatal instinct: 'We observed a statistically significant interaction effect.'","task":"Write the 1-2 sentence answer you'd want quoted.","tips":["Say what happens in the world, not what happened in the stats.","Assume the quote appears with no surrounding context.","Keep the claim inside what the data supports — quotable but honest."],"focus":["audience","precision"],"placeholder":"We found that people remember more when —"},
    {"id":"audience-stu-senior-10","level":"senior","profession":"student","title":"The three-minute-thesis opener","scenario":"You're entering the university's three-minute-thesis competition. The audience is educated but from every discipline. Your current opening line names your subfield and its central debate.","task":"Write an opening 1-2 sentences that hook a general academic audience.","tips":["Open with the question or stake anyone can feel.","Your subfield's debate is an inside conversation — save it or skip it.","Concrete beats clever: a person, a number, a puzzle."],"focus":["audience","impact"]},
    {"id":"audience-stu-senior-11","level":"senior","profession":"student","title":"The stats explanation for a colleague","scenario":"A fellow grad student from a qualitative program asks you to explain what your mixed-effects model actually does — they need to understand it to co-author the discussion section.","task":"Write a 3-4 sentence explanation for a smart colleague with no stats training.","tips":["Anchor to their question: what does the model let us claim?","Use their study's terms, not the model's.","Precision they can't use is noise; give them the working intuition."],"focus":["audience","clarity"]},
    {"id":"audience-stu-senior-12","level":"senior","profession":"student","title":"The undergrad mentee's task briefing","scenario":"You're delegating data coding to your undergraduate assistant. Your draft instructions read like a methods section — passive voice, no examples, terms they haven't met.","task":"Rewrite the task briefing in 3-4 sentences a new assistant can follow without asking.","tips":["Write in second person: 'you open, you tag, you save.'","Give one worked example — it replaces a paragraph of rules.","Say what to do when unsure, so they don't guess silently."],"focus":["audience","clarity"]},
    {"id":"audience-stu-senior-13","level":"senior","profession":"student","title":"The dean's appeal letter","scenario":"You're petitioning the graduate school for a one-semester funding extension. Your draft argues from your research's scientific importance. The dean's office decides based on precedent, policy, and completion likelihood.","task":"Write the opening 2-3 sentences framed around what the dean's office weighs.","tips":["Argue in their currency: completion timeline, policy grounds, precedent.","The science matters only as evidence you'll finish.","Name the specific policy provision if one exists."],"focus":["audience","structure"]},
    {"id":"audience-stu-senior-14","level":"senior","profession":"student","title":"The industry-partner meeting","scenario":"Your lab's industry partner is visiting and you have ten minutes to present your project. Last time, their team checked phones during your theory slides but leaned in at the prototype demo.","task":"Write the first two sentences of a presentation aimed at what the partner values.","tips":["Lead with the application and what it could do for their product.","Theory appears only where it de-risks their decision.","Know their timeline — 'usable in 18 months' is their language."],"focus":["audience","impact"],"placeholder":"This prototype cuts the calibration step your users complain about —"},
    {"id":"audience-stu-senior-15","level":"senior","profession":"student","title":"The methods question at a general seminar","scenario":"After your departmental talk, a professor from a distant subfield asks why you chose your analysis method. Your honest answer is dense with assumptions their area doesn't share.","task":"Write a 2-3 sentence spoken answer that works for a non-specialist academic.","tips":["Answer the underlying question: why this tool for this job.","Name the alternative you rejected and the one-line reason.","Skip the mathematical justification unless asked twice."],"focus":["audience","clarity"]},
    {"id":"audience-stu-senior-16","level":"senior","profession":"student","title":"The high-school outreach visit","scenario":"You're speaking to a high-school science class about your research for fifteen minutes. Your conference talk is the only version you have, and it will lose them by slide two.","task":"Write a 2-3 sentence opening that makes fifteen-year-olds care about your question.","tips":["Start with something from their world your research touches.","Ask them a question they'll want answered.","Wonder transfers better than information — pick your one 'whoa' fact."],"focus":["audience","impact"]},
    {"id":"audience-stu-senior-17","level":"senior","profession":"student","title":"The program administrator's question","scenario":"The graduate program administrator emails asking why your committee meeting hasn't happened this year — she needs a reason for the compliance file, not science. Your draft explains your experimental delays in detail.","task":"Write a 2-3 sentence reply that gives her exactly what the file needs.","tips":["Answer in administrative terms: the reason category and the new date.","One clause of science is plenty.","Ask what form or note she needs from your advisor — close the loop."],"focus":["audience","concision"]},
    {"id":"audience-stu-senior-18","level":"senior","profession":"student","title":"The cross-disciplinary collaborator","scenario":"You're writing to a computer science student about collaborating: you need their ML expertise on your ecology dataset. Your draft is full of field-specific species and site terminology they can't parse.","task":"Rewrite the project pitch in 2-3 sentences using terms a CS student can evaluate.","tips":["Describe your data as data: size, structure, labels, noise.","Frame the problem as their kind of problem — prediction, classification.","Your domain details enter later, as color, not gatekeeping."],"focus":["audience","clarity"],"placeholder":"I have 40,000 labeled audio clips and a classification problem —"},
    {"id":"audience-stu-senior-19","level":"senior","profession":"student","title":"The grandparent test for your title","scenario":"Your working dissertation title is accurate and unreadable: three colons, two subfield terms. Your program's guide suggests a title a relative could roughly understand.","task":"Write two versions of your title: the technical one and one a layperson could parse.","tips":["The lay version keeps the question, drops the taxonomy.","Verbs help: what does the work show or do?","You'll need both — different documents, different readers."],"focus":["audience","concision"]},
    {"id":"audience-stu-senior-20","level":"senior","profession":"student","title":"The mixed seminar room","scenario":"You're giving a talk to the whole department: faculty from your area, grad students from others, a few undergrads. Pitching to the three specialists in row one will lose the other forty people.","task":"Write the first three sentences of a talk that brings the whole room in before going deep.","tips":["One primary audience: pick the smart non-specialist and aim there.","Give the specialists depth in the middle, not the opening.","Signal the flight plan so everyone knows when detail is coming."],"focus":["audience","structure"]},
    {"id":"audience-stu-senior-21","level":"senior","profession":"student","title":"The master's student handoff","scenario":"A first-year master's student is inheriting your side project. Your handoff document assumes doctoral-level familiarity with the literature and your own file conventions.","task":"Write the opening 3-4 sentences of a handoff pitched at their starting point.","tips":["State the project's goal in one plain sentence before any history.","Point to the three files that matter and what each is.","Name the first concrete task they should do this week."],"focus":["audience","structure"]},
    {"id":"audience-stu-senior-22","level":"senior","profession":"student","title":"The career-fair thirty seconds","scenario":"At a university career fair, a company representative asks, 'So what do you work on?' The line behind you is long. Your dissertation elevator pitch is currently ninety seconds of context.","task":"Write a 2-sentence answer tuned to what an employer at a booth listens for.","tips":["Lead with the skill and scale, not the research question.","Mirror their world: product, data, users, results.","End with a question about their team to start a real exchange."],"focus":["audience","concision"],"placeholder":"I spend my days building experiments and analyzing behavioral data at scale —"},
    {"id":"audience-stu-senior-23","level":"senior","profession":"student","title":"The reviewer from the adjacent field","scenario":"Your interdisciplinary paper drew a reviewer from the other parent field. Their comments show they misread your central method because your description assumed your home field's conventions.","task":"Rewrite the 2-3 sentence method description so a reader from either field parses it correctly.","tips":["Find the term that means different things in the two fields — and disambiguate it.","State the convention you're following explicitly, with a citation.","This isn't dumbing down; it's removing a landmine."],"focus":["audience","precision"]},
    {"id":"audience-stu-senior-24","level":"senior","profession":"student","title":"The alumni-magazine paragraph","scenario":"The university's alumni magazine wants a short paragraph on your award-winning research. Readers are proud graduates in every profession; they'll give you eight seconds.","task":"Write a 3-sentence paragraph for a proud but non-specialist readership.","tips":["Lead with the human-scale story or stake.","One number they'll remember beats five they won't.","Let the university's pride do work: what this means for the field or city."],"focus":["audience","impact"]},
    {"id":"audience-stu-senior-25","level":"senior","profession":"student","title":"The office-hours altitude check","scenario":"A struggling student comes to your office hours confused by a concept you've now explained twice the same way. The problem isn't their effort — it's that your explanation starts three levels above where they are.","task":"Write a 3-4 sentence re-explanation that starts from what the student already knows.","tips":["Diagnose first: find the last thing they solidly understand and build from there.","Change the representation — a picture or example, not the same words slower.","Ask a check question at the end to verify the bridge held."],"focus":["audience","clarity"]}
  ],
  "structure-that-carries": [
    {"id":"structure-stu-senior-01","level":"senior","profession":"student","title":"The proposal's governing idea","scenario":"Your thesis proposal currently reads as four loosely related studies. Your advisor's margin note: 'What's the one question this dissertation answers?' You know the studies connect, but the document doesn't say how.","task":"Write the one governing sentence for your dissertation and the three sub-questions beneath it.","tips":["One idea at the top; everything else must hang from it.","If a study doesn't serve the governing question, flag it — don't force it.","Three buckets maximum; four studies may need regrouping."],"focus":["structure","clarity"],"placeholder":"This dissertation asks whether —"},
    {"id":"structure-stu-senior-02","level":"senior","profession":"student","title":"SCQA for the paper intro","scenario":"Your introduction dumps forty citations in rough chronological order. A reader finishes it knowing the literature exists but not why your study needed to happen.","task":"Write your intro's skeleton as SCQA: Situation, Complication, Question, Answer — one sentence each.","tips":["Situation = what the field agrees on; keep it to one sentence.","Complication = the tension or gap that makes the paper necessary.","Your study is the Answer — the intro's job is to make it inevitable."],"focus":["structure","impact"]},
    {"id":"structure-stu-senior-03","level":"senior","profession":"student","title":"PREP for the committee question","scenario":"In committee meetings you answer questions by thinking aloud — starting with background and arriving at your point two minutes in. Your advisor suggested practicing a tighter spoken form.","task":"Using PREP (Point, Reason, Example, Point), write a spoken answer to 'Why did you choose this population?'","tips":["Point first: name the choice and the core reason in sentence one.","One concrete example carries more than three abstract justifications.","Restate the point at the end — it's what the room remembers."],"focus":["structure","clarity"],"placeholder":"I chose bilingual adults because they isolate the variable we care about."},
    {"id":"structure-stu-senior-04","level":"senior","profession":"student","title":"The messy reviewer response letter","scenario":"You have 23 reviewer comments across three reviewers, and your response letter currently addresses them in the order they arrived. Major concerns are buried between typo fixes.","task":"Write the grouping scheme for your response letter: 3-4 headers and what goes under each.","tips":["Group by theme, not by reviewer — the editor reads for issues.","Lead with the biggest concern, resolved; end with the trivia.","A one-paragraph summary of major changes up top orients everyone."],"focus":["structure","audience"]},
    {"id":"structure-stu-senior-05","level":"senior","profession":"student","title":"The lab-meeting slide deck","scenario":"Your lab-meeting presentations follow your workflow: what you did Monday, then Tuesday. Your labmates lose the thread because chronology isn't an argument.","task":"Write the titles of the five slides that would carry your update as an argument, not a diary.","tips":["Each slide title is a claim, not a topic: 'Yield doubles under X,' not 'Results.'","Order by logic — finding, evidence, implication — not by calendar.","If a slide title can't be a sentence, the slide has no point yet."],"focus":["structure","clarity"]},
    {"id":"structure-stu-senior-06","level":"senior","profession":"student","title":"The fellowship research statement","scenario":"Your fellowship statement must cover past work, current project, and future plans in two pages. Your draft interleaves all three, and reviewers can't tell where you've been from where you're going.","task":"Write the three-part skeleton: one governing sentence for the statement, plus a one-line topic sentence for each section.","tips":["The governing idea links all three: a trajectory, not three episodes.","Each section's first line should preview its whole content.","Reviewers skim topic sentences — make them load-bearing."],"focus":["structure","impact"]},
    {"id":"structure-stu-senior-07","level":"senior","profession":"student","title":"The conference talk's spine","scenario":"You have twelve minutes at a conference for work that took two years. Your current outline is your paper's structure — intro, methods, results, discussion — which fits a reader, not a listener.","task":"Write the 4-beat spine of the talk: hook, question, key result, implication — one sentence per beat.","tips":["Listeners can't re-read; each beat must set up the next.","One key result presented well beats four presented fast.","Design the last sentence first — it's the one they'll quote."],"focus":["structure","impact"]},
    {"id":"structure-stu-senior-08","level":"senior","profession":"student","title":"The literature-notes pile","scenario":"You've read 60 papers for your comprehensive exam and your notes are one long chronological document. The exam is in six weeks and you can't retrieve anything.","task":"Write the 3-4 thematic buckets you'd reorganize the notes into, with a one-line description of each.","tips":["Buckets should mirror the debates, not the decades.","Test each bucket: could it be an exam question's answer?","Papers that fit nowhere are either a new bucket or not exam-relevant."],"focus":["structure","clarity"]},
    {"id":"structure-stu-senior-09","level":"senior","profession":"student","title":"The quals answer under structure","scenario":"In your qualifying exam, you'll get broad questions like 'How has theory X evolved?' Your practice answers wander — you know too much and organize too little.","task":"Write the first two sentences of a structured spoken answer that previews its own shape.","tips":["Signpost immediately: 'Three phases: A, B, C. Starting with A —'","The preview is a promise; keep the answer inside it.","Examiners grade organization as understanding — because it is."],"focus":["structure","clarity"],"placeholder":"The theory evolved in three phases —"},
    {"id":"structure-stu-senior-10","level":"senior","profession":"student","title":"The grant aims page","scenario":"Your grant application's aims page lists three aims that read as three separate projects. The program officer's feedback on a colleague's similar draft: 'What's the payoff if all three succeed?'","task":"Write the one-sentence payoff statement, then one sentence per aim showing how each serves it.","tips":["Aims are pillars under one roof — build the roof sentence first.","Each aim sentence: what you'll do and what it contributes to the payoff.","Aims should be independent (one can fail) but convergent (all serve the goal)."],"focus":["structure","impact"]},
    {"id":"structure-stu-senior-11","level":"senior","profession":"student","title":"The poster's reading order","scenario":"Your conference poster is a paper exploded onto a board — dense columns, no entry point. Watching people at the last conference, they looked for ten seconds and moved on.","task":"Write the poster's visual hierarchy: the headline claim, the three panels, and what a 10-second reader should take away.","tips":["The title should state the finding, not the topic.","Design for three readers: 10 seconds, 2 minutes, 10 minutes.","Every panel needs a one-line takeaway a passerby can catch."],"focus":["structure","audience"]},
    {"id":"structure-stu-senior-12","level":"senior","profession":"student","title":"The teaching statement's frame","scenario":"Your teaching statement for academic jobs is a list of courses TA'd and techniques used. Search committees read hundreds; lists don't survive the first cut.","task":"Write the governing idea of your teaching statement and the 2-3 claims that support it.","tips":["Lead with your teaching philosophy as one arguable sentence.","Each claim gets one vivid classroom example as evidence.","The courses list is an appendix fact, not the structure."],"focus":["structure","impact"]},
    {"id":"structure-stu-senior-13","level":"senior","profession":"student","title":"The methods section a reader can follow","scenario":"Your methods section is complete but unnavigable — procedures, materials, and analyses tangled in narrative order. Your co-author keeps asking where things are.","task":"Write the subsection structure you'd impose, with one line on what lives in each.","tips":["Standard skeletons exist for a reason — deviate only with cause.","Group by function (participants, materials, procedure, analysis), not chronology.","Each subsection's first sentence should orient: what and why."],"focus":["structure","clarity"]},
    {"id":"structure-stu-senior-14","level":"senior","profession":"student","title":"The job-talk architecture","scenario":"Your academic job talk must serve a department where only two people share your specialty. Forty-five minutes, one shot. Your draft is your three thesis studies presented sequentially.","task":"Write the talk's architecture: opening claim, the throughline connecting the studies, and the closing future-directions frame.","tips":["The talk argues for you, not just the work: one research vision, evidenced by studies.","The throughline sentence should appear at every transition.","End on where the program goes — hiring is a bet on your future."],"focus":["structure","impact"]},
    {"id":"structure-stu-senior-15","level":"senior","profession":"student","title":"The three-request email","scenario":"You're emailing your advisor with three unrelated needs: a signature on a form, feedback on a draft, and a decision about summer funding. Your draft weaves them into one paragraph; historically, only the first gets answered.","task":"Restructure the email: a one-line opener, then the three asks in a scannable form.","tips":["Number the asks — replies track numbers.","Order by deadline, and put each deadline with its ask.","One-line opener says 'three things' so nothing gets lost."],"focus":["structure","concision"],"placeholder":"Three things this week, in deadline order:"},
    {"id":"structure-stu-senior-16","level":"senior","profession":"student","title":"The dissertation chapter map","scenario":"You're starting to write your dissertation and the graduate school template tells you formatting, not logic. Chapters 2 and 3 could go in either order and you can't articulate why one wins.","task":"Write a one-sentence purpose statement for each chapter showing how each sets up the next.","tips":["Each chapter should leave the reader needing the next one.","If two chapters swap freely, neither is doing structural work yet.","The purpose sentences become your introduction's roadmap paragraph."],"focus":["structure","clarity"]},
    {"id":"structure-stu-senior-17","level":"senior","profession":"student","title":"The protocol document","scenario":"You're writing the definitive protocol for your lab's new assay so it survives after you graduate. Your draft mixes the why, the how, and the troubleshooting into one stream.","task":"Write the document's section structure with one line on what each section contains and who uses it.","tips":["Separate layers: quick-reference steps, full rationale, troubleshooting table.","The person mid-experiment needs steps, not history — front-load them.","Version and date it; future users need to trust it's current."],"focus":["structure","audience"]},
    {"id":"structure-stu-senior-18","level":"senior","profession":"student","title":"The funder's progress report","scenario":"Your fellowship requires an annual progress report. Your draft narrates the year month by month, including the two months where nothing worked.","task":"Write the report's structure: 3-4 headers organized around commitments made vs. delivered.","tips":["Structure around the original aims: promised, delivered, changed.","Funders read for accountability and trajectory, not diary.","Deviations get their own header with rationale — hiding them reads worse."],"focus":["structure","precision"]},
    {"id":"structure-stu-senior-19","level":"senior","profession":"student","title":"The office-hours explanation pattern","scenario":"Students leave your office hours saying 'that makes sense' and then fail the same problem type. Your explanations solve the instance but never surface the structure of the method.","task":"Write a reusable 3-step spoken structure for explaining any problem type, then apply it to one example.","tips":["Name the pattern first: 'This is a conservation problem.'","Then the decision rule: how they'd recognize it next time.","Solve the instance last — it's the illustration, not the lesson."],"focus":["structure","audience"]},
    {"id":"structure-stu-senior-20","level":"senior","profession":"student","title":"The recruitment-day talk","scenario":"You're presenting your lab to prospective grad students on visit day. Ten minutes to convey what the lab studies, how it works, and why they'd thrive. Your draft is a tour of every current project.","task":"Write the three-part structure that would serve a prospective student's actual decision.","tips":["Their question is 'what would MY life here be?' — structure around it.","One flagship project as depth; the rest as one-line breadth.","End with the concrete: funding, mentorship style, where alumni went."],"focus":["structure","audience"]},
    {"id":"structure-stu-senior-21","level":"senior","profession":"student","title":"The rebuttal under a word limit","scenario":"The conference gives you 500 words to rebut three reviews. Your draft responds line by line and is at 900 words with the biggest issue still half-addressed.","task":"Write the rebuttal's structure: what gets words, what gets one line, what gets conceded.","tips":["Triage: the one issue that decides accept/reject gets half the budget.","Concede small points fast — concession buys credibility for the fight that matters.","One header per reviewer wastes structure; one per issue spends it."],"focus":["structure","concision"]},
    {"id":"structure-stu-senior-22","level":"senior","profession":"student","title":"The workshop you're running","scenario":"You're leading a 90-minute methods workshop for your department. Your plan is currently a stack of content with no arc — no opening promise, no checkpoints, no landing.","task":"Write the workshop's arc: the opening promise, 2-3 blocks with checkpoints, and the closing consolidation.","tips":["Open with what they'll be able to DO by the end.","Every 25-30 minutes, a checkpoint: they apply, you verify.","The last ten minutes consolidate — never introduce new material there."],"focus":["structure","audience"]},
    {"id":"structure-stu-senior-23","level":"senior","profession":"student","title":"The results section's argument","scenario":"Your results section presents analyses in the order you ran them, including two dead ends. Your co-author asks: 'What story do the results tell, in what order?'","task":"Write the results section's paragraph-level outline: one claim per paragraph, in argumentative order.","tips":["Order by logic: main effect, then robustness, then boundary conditions.","Dead-end analyses go to supplementary or the discussion's honesty paragraph.","Each paragraph's first sentence states the finding; stats support, not lead."],"focus":["structure","clarity"]},
    {"id":"structure-stu-senior-24","level":"senior","profession":"student","title":"The committee-feedback synthesis","scenario":"Your four committee members gave you feedback that partly conflicts: two want more studies, one wants fewer, one wants a reframe. You need to send a synthesis and plan to all of them.","task":"Write the structure of a synthesis email: how you group the feedback and present your integrated plan.","tips":["Group by decision, not by person — no one wants their comment ranked.","Where members conflict, name the tension neutrally and state your proposed resolution.","End with the plan as numbered commitments with dates."],"focus":["structure","impact"]},
    {"id":"structure-stu-senior-25","level":"senior","profession":"student","title":"The five-minute version","scenario":"A visiting professor asks about your research in the hallway, and your advisor waves you in: 'Give her the five-minute version.' You have an hour talk and a fifteen-second pitch, but nothing in between.","task":"Write the outline of the five-minute version: the four beats and one sentence per beat.","tips":["The five-minute version is a structure, not a compression — pick beats, don't talk faster.","Question, approach, key finding, why it matters. One beat each.","Leave one deliberate opening for a question — conversation beats lecture."],"focus":["structure","concision"],"placeholder":"The question driving my work is —"}
  ],
  "cut-to-the-bone": [
    {"id":"concise-stu-senior-01","level":"senior","profession":"student","title":"The hedge-stuffed abstract","scenario":"Your abstract says your findings 'may potentially suggest a possible role' for your variable. Two hedges per claim — your advisor circled them all. The data are solid.","task":"Rewrite the central claim with exactly one calibrated hedge.","tips":["Pick the one hedge that reflects real uncertainty; delete the reflexive ones.","'Suggests' already hedges — 'may suggest' hedges the hedge.","Precision about uncertainty beats vagueness about it."],"focus":["concision","precision"],"placeholder":"These results suggest that —"},
    {"id":"concise-stu-senior-02","level":"senior","profession":"student","title":"The 300-word email, halved","scenario":"Your email to your advisor about switching statistical approaches runs 300 words. Rereading, you see meta-commentary ('I wanted to reach out about'), backstory, and the same point made twice.","task":"Rewrite the email in under 100 words without losing the decision or the reason.","tips":["Delete every sentence about the email itself.","State the switch, the one-line reason, and the ask.","If a detail doesn't change their answer, it goes."],"focus":["concision","clarity"]},
    {"id":"concise-stu-senior-03","level":"senior","profession":"student","title":"The nominalization sweep","scenario":"Your methods draft reads: 'The implementation of the randomization of participants was conducted prior to the administration of the intervention.' Your writing-group partner underlined it and wrote 'who did what?'","task":"Rewrite the sentence with verbs doing the work.","tips":["Hunt the -tion words: each one is a verb in a trench coat.","'We randomized participants before the intervention' — subject, verb, object.","Passive voice plus nominalization is how sentences die."],"focus":["concision","clarity"],"placeholder":"We randomized participants —"},
    {"id":"concise-stu-senior-04","level":"senior","profession":"student","title":"The talk's throat-clearing","scenario":"Your conference talk opens: 'So, um, today I'm going to be talking about some work we've been doing in our lab over the past couple of years on the topic of...' Twenty seconds gone, nothing said.","task":"Write an opening sentence that starts the talk inside the science.","tips":["Delete the announcement that you will begin; just begin.","Your first ten seconds set the room's attention budget.","A question or a finding — either beats a preamble."],"focus":["concision","impact"],"placeholder":"Half of published effects in our field fail to replicate. Ours didn't — here's why."},
    {"id":"concise-stu-senior-05","level":"senior","profession":"student","title":"The 150-word abstract limit","scenario":"The conference caps abstracts at 150 words. Yours is at 240 and everything feels essential: background, gap, method, two findings, implication.","task":"Cut the abstract to 150 words, preserving the finding and its significance.","tips":["Background gets one sentence — reviewers know the field.","One finding presented fully beats two presented thinly.","Cut adjectives first, then clauses, then the weakest sentence whole."],"focus":["concision","structure"]},
    {"id":"concise-stu-senior-06","level":"senior","profession":"student","title":"The redundant-pair habit","scenario":"Your dissertation draft is full of pairs: 'aims and objectives,' 'methods and approaches,' 'important and significant.' Each pair says one thing twice, and there are dozens.","task":"Rewrite three sentences from your writing, collapsing every redundant pair to the stronger word.","tips":["Twin nouns rarely add meaning — pick the truer one.","'Significant' has a technical meaning in your field; don't spend it decoratively.","Every deleted word raises the density of what remains."],"focus":["concision","precision"]},
    {"id":"concise-stu-senior-07","level":"senior","profession":"student","title":"The slide with eighty words","scenario":"Your lab-meeting slide has three full paragraphs on it. You read it aloud to the room, which means nobody listens and nobody reads.","task":"Rewrite the slide's text as a claim headline plus at most three short bullets.","tips":["The headline states the takeaway; the bullets carry evidence.","Six words per bullet is a discipline worth faking until real.","If it must be said, say it — the slide only needs to anchor it."],"focus":["concision","structure"]},
    {"id":"concise-stu-senior-08","level":"senior","profession":"student","title":"The apologetic email opener","scenario":"Your emails to professors open with 'Sorry to bother you, I know you're incredibly busy, and this is probably a silly question, but...' — three apologies before content.","task":"Rewrite the opener to be direct and respectful in one sentence.","tips":["Respect is shown by brevity, not apology.","A precise question honors their time more than a cushioned one.","One courtesy clause maximum: 'When you have a moment —'"],"focus":["concision","impact"],"placeholder":"Quick question about the assigned reading:"},
    {"id":"concise-stu-senior-09","level":"senior","profession":"student","title":"The over-caveated result","scenario":"Your results paragraph spends four sentences on limitations before stating the finding, then two more after. The caveats outweigh the claim three to one, and the finding is real.","task":"Rewrite the paragraph: the finding stated plainly, then the one caveat that matters.","tips":["State the result first, cleanly, in one sentence.","Choose the single limitation a skeptic would raise first.","A limitations section exists — the results paragraph isn't it."],"focus":["concision","precision"]},
    {"id":"concise-stu-senior-10","level":"senior","profession":"student","title":"The personal statement bloat","scenario":"Your fellowship personal statement is 200 words over the limit. The overage is childhood backstory and phrases like 'I have always been passionate about the pursuit of knowledge.'","task":"Cut 200 words by removing generic passion claims and keeping specific evidence.","tips":["'Passionate' is claimed; evidence is shown — keep only what shows.","The childhood story earns its place only if it's unlike anyone else's.","Every reviewer cliché you cut makes the rest sound more like you."],"focus":["concision","impact"]},
    {"id":"concise-stu-senior-11","level":"senior","profession":"student","title":"The meta-commentary purge","scenario":"Your dissertation chapter announces itself constantly: 'In this section, we will discuss...', 'As mentioned previously...', 'It is worth noting that...' Ten percent of your words are about the words.","task":"Rewrite a 4-sentence passage from your writing with all meta-commentary removed.","tips":["'It is worth noting that X' means 'X' — say X.","Structure should be visible from headings and logic, not narration.","'As mentioned previously' usually flags a repetition to cut, not link."],"focus":["concision","clarity"]},
    {"id":"concise-stu-senior-12","level":"senior","profession":"student","title":"The conference bio","scenario":"The symposium wants a 50-word bio. Your draft is 130 words listing every affiliation, award, and interest since undergrad.","task":"Write the 50-word bio that keeps only what this audience needs.","tips":["Current position, research focus, one distinguishing fact.","Awards belong if this audience would recognize them; otherwise cut.","Write it in third person and read it aloud — it will be read aloud."],"focus":["concision","audience"]},
    {"id":"concise-stu-senior-13","level":"senior","profession":"student","title":"The double-length discussion","scenario":"Your paper's discussion section restates every result before interpreting it — the reader gets the results section twice. Your co-author's comment: 'Half of this is upstairs already.'","task":"Rewrite one discussion paragraph to interpret without re-narrating.","tips":["Reference results by their meaning, not by re-description.","The discussion's job: so what, compared to what, what next.","If a sentence would fit in results, it's in the wrong section."],"focus":["concision","structure"]},
    {"id":"concise-stu-senior-14","level":"senior","profession":"student","title":"The Slack message to the busy PI","scenario":"Your PI answers Slack between meetings on their phone. Your last message was twelve lines; the answer you needed was yes/no. You got no reply for two days.","task":"Rewrite the message so the yes/no question fits in the phone's first notification line.","tips":["The question goes first — notification previews show ~10 words.","Context follows for if they need it; usually they won't.","Offer a default: 'unless I hear otherwise, I'll do X' unblocks you either way."],"focus":["concision","impact"],"placeholder":"OK to submit the abstract without the pilot data? Context below."},
    {"id":"concise-stu-senior-15","level":"senior","profession":"student","title":"The tightened rebuttal","scenario":"Your response to one reviewer comment runs 400 words of literature justification. The reviewer asked a simple question: why n=40? The answer is a power analysis.","task":"Rewrite the response in 2-3 sentences with the number doing the arguing.","tips":["Lead with the power analysis result — that IS the answer.","Cite one precedent, not seven.","Long defenses read as insecurity; short ones as confidence."],"focus":["concision","precision"],"placeholder":"A priori power analysis required n=38 for 80% power —"},
    {"id":"concise-stu-senior-16","level":"senior","profession":"student","title":"The teaching reflection, trimmed","scenario":"Your TA program requires an end-of-term reflection. Your draft is 800 words of course diary; the requirement is 300 words of what you learned and would change.","task":"Write the 3-sentence core: what worked, what didn't, what you'll change.","tips":["One concrete example per claim — the rest of the diary goes.","'What I'd change' is the sentence the reader actually wants.","Reflection means judgment, not chronology."],"focus":["concision","structure"]},
    {"id":"concise-stu-senior-17","level":"senior","profession":"student","title":"The grant budget justification","scenario":"Your budget justification explains each item with paragraphs of pleading. The reviewer's checklist has one question per line item: is it necessary and priced right?","task":"Rewrite two line-item justifications in one sentence each.","tips":["Item, cost, and the aim it serves — one sentence carries all three.","Delete adjectives like 'crucial' and 'essential'; necessity shows in logic.","Reviewers reward justifications that respect the checklist."],"focus":["concision","precision"]},
    {"id":"concise-stu-senior-18","level":"senior","profession":"student","title":"The poster text diet","scenario":"Your poster draft has 1,100 words. The poster veterans in your lab say a good poster has 400 and the best conversations happen off the board.","task":"Choose one poster section and cut its text by 60% while keeping the claim.","tips":["Turn sentences into labeled figures wherever data exists.","Methods compress hardest: a flow diagram replaces a paragraph.","The poster is the trailer; you are the movie."],"focus":["concision","audience"]},
    {"id":"concise-stu-senior-19","level":"senior","profession":"student","title":"The three-sentence research summary","scenario":"A grant portal asks for your project in three sentences, and it will be the first thing every panelist reads. Your current draft is your abstract's first three sentences, which lean entirely on background.","task":"Write three sentences: what you're doing, why it matters, what success looks like.","tips":["One job per sentence — don't let background colonize all three.","Concrete nouns and active verbs survive panel fatigue.","Read it as a tired reviewer at 11pm: does it still land?"],"focus":["concision","impact"]},
    {"id":"concise-stu-senior-20","level":"senior","profession":"student","title":"The LinkedIn about section","scenario":"You're building a LinkedIn profile for your industry transition. Your draft 'About' section is your CV in paragraph form — 350 words nobody will finish.","task":"Write a 3-4 sentence About section that leads with what you do and want next.","tips":["First line: the capability, in industry words.","One proof point with a number.","Last line: what you're looking for — recruiters search for intent."],"focus":["concision","audience"],"placeholder":"I turn messy behavioral data into decisions."},
    {"id":"concise-stu-senior-21","level":"senior","profession":"student","title":"The minutes that became a transcript","scenario":"You took minutes for the lab's monthly meeting and your draft records everything everyone said, in order. The lab needs decisions and action items, not a court record.","task":"Rewrite the minutes as decisions made and actions assigned, in under 8 lines.","tips":["Two headers: Decided, and Who-does-what-by-when.","Discussion that changed no decision is history, not minutes.","Names and dates on every action — vague minutes create vague follow-through."],"focus":["concision","structure"]},
    {"id":"concise-stu-senior-22","level":"senior","profession":"student","title":"The 280-character announcement","scenario":"Your paper is out and you're announcing it on academic social media. Your draft thread is nine posts; experience says engagement dies after the first.","task":"Write the single 280-character post that carries the finding and the link's reason to click.","tips":["The finding, in plain words, with its most striking number.","Write for the retweet: someone else must want to repeat it.","The thread can exist — the first post must not need it."],"focus":["concision","impact"]},
    {"id":"concise-stu-senior-23","level":"senior","profession":"student","title":"The filler-word ledger","scenario":"You recorded your practice defense talk and counted: 'sort of' 31 times, 'basically' 22, 'you know' 14. Each one shaves authority off a claim you can actually defend.","task":"Write out your key claim as you'd say it, then write the filler-free spoken version.","tips":["'Sort of significant' is not a statistical concept — commit or qualify precisely.","A pause carries confidence; filler leaks it.","Practice the clean version aloud three times; muscle memory is the fix."],"focus":["concision","impact"]},
    {"id":"concise-stu-senior-24","level":"senior","profession":"student","title":"The email chain summary","scenario":"A 14-message thread between you, your advisor, and a collaborator needs summarizing for the new co-author joining the paper. Forwarding the chain would take them an hour to decode.","task":"Write a 3-4 sentence summary: current state, open question, and what's needed from them.","tips":["They need the state of play, not the plot.","One open decision, clearly framed, with the options.","Their action goes last and unmissable."],"focus":["concision","clarity"]},
    {"id":"concise-stu-senior-25","level":"senior","profession":"student","title":"The halved paragraph","scenario":"Pick the densest paragraph from your current chapter draft — the one you're proudest of. Your writing group's standing challenge: any paragraph can lose half its words and gain force.","task":"Rewrite the paragraph at half length without dropping a claim.","tips":["First pass: delete hedges, meta-commentary, redundant pairs.","Second pass: merge sentences that share a subject.","What survives is what you actually meant."],"focus":["concision","clarity"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-stu-senior-01","level":"senior","profession":"student","title":"The 'significantly improved' trap","scenario":"Your draft claims the intervention 'significantly improved performance.' Your advisor's comment: 'Statistically or substantially? By how much? Say the number.'","task":"Rewrite the claim with the effect size and what it means in real terms.","tips":["Give the magnitude, not just the verdict: 12% faster, d = 0.6.","Translate the number: what does a reader feel or see at that size?","'Significant' answers one narrow question; your sentence should answer more."],"focus":["precision","clarity"],"placeholder":"The intervention cut response times by 12% (d = 0.58) —"},
    {"id":"precision-stu-senior-02","level":"senior","profession":"student","title":"One insight from the data dump","scenario":"You have six panels of results for lab meeting and you're planning to show all of them. Your PI's standing question after every figure: 'What's the one thing this tells us?'","task":"Write the one-sentence insight your strongest figure supports.","tips":["An insight is a claim about the world, not a description of the plot.","'X increases with Y' is a pattern; 'which means Z' is the insight.","If the sentence works without the figure, you've found it."],"focus":["precision","impact"]},
    {"id":"precision-stu-senior-03","level":"senior","profession":"student","title":"The 'recently' problem","scenario":"Your intro says the debate 'has recently attracted attention' citing papers from 2009. Your literature is precise; your time words aren't — 'recently,' 'traditionally,' 'in recent years' pepper the draft.","task":"Rewrite two sentences replacing vague time markers with dates or ranges.","tips":["'Since 2015' survives review; 'recently' invites a margin note.","Vague time words also date badly — your paper will be read in five years.","If you can't pin the date, the claim may need checking, not softening."],"focus":["precision","clarity"]},
    {"id":"precision-stu-senior-04","level":"senior","profession":"student","title":"What, So What, Now What","scenario":"You're reporting an unexpected finding to your advisor: a control condition showed the effect too. You keep describing the anomaly without saying what it means or what you propose.","task":"Write three sentences: What (the observation), So What (the implication), Now What (your proposed next step).","tips":["What = just the facts, with numbers.","So What = the interpretation that matters most if true.","Now What = a concrete, decidable proposal — that's what makes it a report, not a worry."],"focus":["precision","structure"],"placeholder":"The control condition also showed the effect (p = .003)."},
    {"id":"precision-stu-senior-05","level":"senior","profession":"student","title":"The skeptic test","scenario":"Your discussion claims your findings 'demonstrate the mechanism.' Your most skeptical committee member will read this. You have correlational evidence and one indirect manipulation.","task":"Rewrite the claim at the strength your evidence actually supports.","tips":["Match the verb to the design: correlational data 'is consistent with,' not 'demonstrates.'","Pre-run the skeptic: what's the first hole they'd poke?","A defensible claim survives the defense; an inflated one becomes the defense."],"focus":["precision","impact"]},
    {"id":"precision-stu-senior-06","level":"senior","profession":"student","title":"The 'many studies' fix","scenario":"Your lit review says 'many studies have shown' and 'it is widely accepted that' — your writing group asked: how many? which ones? accepted by whom?","task":"Rewrite one such sentence with a countable, citable claim.","tips":["'Twelve of fourteen studies since 2018' beats 'many studies.'","If you haven't counted, 'many' is a guess wearing a suit.","Meta-analyses exist to make this sentence precise — cite one."],"focus":["precision","clarity"]},
    {"id":"precision-stu-senior-07","level":"senior","profession":"student","title":"The timeline your advisor can hold","scenario":"Asked when the chapter draft will be ready, you keep saying 'soon' and 'in a few weeks.' Your advisor has started asking someone else's students how long things take.","task":"Write a 2-sentence commitment with a date and the one dependency that could move it.","tips":["A date creates trust even when it later moves; 'soon' never does.","Name the dependency now — it's your legitimate escape clause.","Pad honestly once, rather than optimistically three times."],"focus":["precision","impact"],"placeholder":"Full draft by Friday, March 21 —"},
    {"id":"precision-stu-senior-08","level":"senior","profession":"student","title":"The quantified teaching record","scenario":"Your academic job application says you have 'extensive teaching experience.' The search committee sees that phrase in every file. You've TA'd 7 courses, guest-lectured 5 times, and your evaluations average 4.6/5.","task":"Rewrite the claim with the numbers doing the work.","tips":["Count everything countable: courses, students, terms, ratings.","'Extensive' is the reader's judgment to make — give them the inputs.","One standout number with context beats five bare ones."],"focus":["precision","impact"],"placeholder":"I've taught 7 courses across 5 terms — roughly 600 students —"},
    {"id":"precision-stu-senior-09","level":"senior","profession":"student","title":"The p-value that ate the sentence","scenario":"Your results sentence reads: 'The effect was significant (F(1,58) = 9.42, p = .003, η² = .14).' Statistically complete — but the sentence never says what actually happened, in which direction, or how much.","task":"Rewrite the sentence so a reader learns the finding before the parentheses.","tips":["Direction and magnitude in words; statistics in support.","'Participants in X recalled 23% more than Y' — then the parenthetical.","The stats certify the claim; they aren't the claim."],"focus":["precision","clarity"]},
    {"id":"precision-stu-senior-10","level":"senior","profession":"student","title":"The compute request","scenario":"You're requesting cluster time from the department's research computing committee. Your draft asks for 'substantial GPU resources for a large-scale project.' The committee allocates in node-hours.","task":"Write a 2-3 sentence request with the exact resources, duration, and justification.","tips":["Ask in their units: node-hours, GPUs, storage, months.","Show the arithmetic: runs × hours per run = the ask.","A precise ask can be granted as-is; a vague one starts a negotiation."],"focus":["precision","clarity"]},
    {"id":"precision-stu-senior-11","level":"senior","profession":"student","title":"The authorship contribution line","scenario":"The journal requires an author-contribution statement. Your draft says you 'contributed to the study.' You designed the second experiment, ran all analyses, and wrote the first draft.","task":"Write your contribution statement naming exactly what you did.","tips":["Verbs and objects: designed X, analyzed Y, wrote Z.","Underclaiming here costs you in job applications later.","Standard taxonomies (CRediT) exist — use their categories."],"focus":["precision","impact"]},
    {"id":"precision-stu-senior-12","level":"senior","profession":"student","title":"The limitation, precisely drawn","scenario":"Your limitations paragraph says the findings 'may not generalize.' Generalize to whom, from whom? Your sample was undergraduates at one university, aged 18-24, 70% female.","task":"Write a 2-sentence limitation that names the specific boundary and its likely direction of bias.","tips":["Name the population you can speak to and the one you can't.","Say which way the bias likely runs — that's analysis, not confession.","Precise limitations read as rigor; vague ones as ritual."],"focus":["precision","clarity"]},
    {"id":"precision-stu-senior-13","level":"senior","profession":"student","title":"The 'promising results' upgrade","scenario":"Your fellowship progress report calls your pilot 'promising.' The panel that renews your funding wants to know what the pilot showed and what it justifies doing next.","task":"Rewrite the sentence with the pilot's key number and the decision it supports.","tips":["'Promising' is a mood; '8 of 10 subjects showed the effect' is a fact.","Connect the number to the next step it licenses.","Funders renew evidence, not optimism."],"focus":["precision","impact"],"placeholder":"The pilot showed the effect in 8 of 10 subjects —"},
    {"id":"precision-stu-senior-14","level":"senior","profession":"student","title":"The benchmark comparison","scenario":"Your talk claims your model 'outperforms existing approaches.' The obvious next question from any audience: which approaches, on what metric, by how much, on whose data?","task":"Rewrite the claim with the comparison fully specified in one sentence.","tips":["Name the baseline, the dataset, the metric, and the margin.","A specified win is smaller but unassailable.","If the full specification embarrasses the claim, the claim was borrowed."],"focus":["precision","clarity"],"placeholder":"Our model beats the standard baseline by 4.2 points of accuracy on —"},
    {"id":"precision-stu-senior-15","level":"senior","profession":"student","title":"The disagreement, pinpointed","scenario":"You disagree with Reviewer 1's claim that your design confounds two variables. Your draft response argues broadly that the design is sound. Your co-author suggests: locate the exact sentence where you and the reviewer diverge.","task":"Write 2-3 sentences that name the precise point of disagreement and your evidence on it.","tips":["Agree with everything you actually agree with first — it isolates the real dispute.","Quote the reviewer's specific claim, then answer that claim.","One targeted counter-argument beats a general defense."],"focus":["precision","structure"]},
    {"id":"precision-stu-senior-16","level":"senior","profession":"student","title":"The outreach impact number","scenario":"Your fellowship renewal asks about broader impacts. Your draft says your science-outreach program 'reached many local students.' You have the records: 6 school visits, 340 students, 4 teachers now using your materials.","task":"Rewrite the impact claim with the numbers and one concrete outcome.","tips":["Count reach, but also name one downstream effect — materials adopted, club formed.","Small precise numbers beat large vague ones.","Keep a running impact log; future-you writes these yearly."],"focus":["precision","impact"]},
    {"id":"precision-stu-senior-17","level":"senior","profession":"student","title":"The 'a lot of data' sentence","scenario":"Your methods say you collected 'a large amount of behavioral data.' Your dataset: 84 participants, 3 sessions each, 1,200 trials per session — roughly 300,000 trials.","task":"Rewrite the sentence with the actual scale.","tips":["Numbers convey scale better than adjectives ever will.","Structure the count: participants × sessions × trials.","Reviewers calibrate rigor partly by whether you count precisely."],"focus":["precision","concision"],"placeholder":"We collected ~300,000 trials (84 participants × 3 sessions × 1,200 trials)."},
    {"id":"precision-stu-senior-18","level":"senior","profession":"student","title":"The calibrated confidence statement","scenario":"Your advisor asks how confident you are that the effect is real before you both commit to a replication study. 'Pretty confident' is your instinct — but the decision needs more resolution than that.","task":"Write a 2-3 sentence spoken answer that states your confidence level and what it rests on.","tips":["Give a graded answer: which parts you'd bet on, which you wouldn't.","Name what evidence would change your mind — that's what calibration means.","Your advisor is pricing a decision; give them usable odds."],"focus":["precision","clarity"]},
    {"id":"precision-stu-senior-19","level":"senior","profession":"student","title":"The exact citation in the rebuttal","scenario":"A reviewer claims your finding contradicts 'the established literature.' You know the literature is actually split, and two major papers support you. Your draft response says 'other work supports our finding.'","task":"Rewrite the response naming the specific papers and what each found.","tips":["Meet a vague appeal to authority with named, dated evidence.","One sentence per supporting paper: authors, year, finding.","Characterize the split honestly — it makes your side credible."],"focus":["precision","impact"]},
    {"id":"precision-stu-senior-20","level":"senior","profession":"student","title":"The demo-day claim","scenario":"You're presenting your prototype to your lab's industry visitors and want to say it's 'much faster than the current tool.' You benchmarked it: 3.1× faster on standard inputs, but 1.2× on the largest files.","task":"Write the one-sentence performance claim that includes the boundary honestly.","tips":["Report the range, not just the peak: '3× on typical inputs, 1.2× on the largest.'","The audience will test the edge case — get there first.","Honest boundaries make the headline number believable."],"focus":["precision","audience"]},
    {"id":"precision-stu-senior-21","level":"senior","profession":"student","title":"The availability email","scenario":"A committee member asks when you're free to meet. Your reply, 'I'm pretty flexible next week,' guarantees two more emails. You are actually free Tuesday afternoon and Thursday before noon.","task":"Write a one-sentence reply that ends the scheduling thread.","tips":["Offer 2-3 specific slots with times and timezone.","'Flexible' transfers the work to the busier person.","Include the meeting length so they can slot it in one look."],"focus":["precision","concision"],"placeholder":"I can do Tuesday 2-5pm or Thursday 9-12 — 45 minutes should cover it."},
    {"id":"precision-stu-senior-22","level":"senior","profession":"student","title":"The thesis-timeline commitment","scenario":"Your committee wants a completion timeline. Your draft lists chapter names with quarters attached, but no dependencies — and last year's version of this same document slipped by six months without explanation.","task":"Write a 3-4 line timeline with dates, dependencies, and the one milestone that determines the rest.","tips":["Identify the critical path: which milestone moves everything behind it.","Attach each date to its dependency: 'defense in May, assuming data collection ends January.'","Acknowledge last year's slip and what's different — credibility must be rebuilt explicitly."],"focus":["precision","structure"]},
    {"id":"precision-stu-senior-23","level":"senior","profession":"student","title":"The error bar explanation","scenario":"At your poster, an undergraduate asks what the error bars on your key figure mean. You realize 'standard error' is a label, not an explanation — and half the researchers who walk by couldn't say precisely either.","task":"Write a 2-sentence spoken explanation of what your error bars let a viewer conclude.","tips":["Explain in terms of the comparison: 'bars that don't overlap here suggest —'","Name what the bars are (SE, SD, CI) because they license different conclusions.","If you can't explain your own uncertainty display, the figure needs work."],"focus":["precision","audience"]},
    {"id":"precision-stu-senior-24","level":"senior","profession":"student","title":"The job-talk improvement number","scenario":"Your industry job talk says your method 'greatly improves' the standard analysis pipeline. The hiring panel of engineers will want a number, its conditions, and its cost.","task":"Write the one-sentence claim with the gain, the condition, and the tradeoff.","tips":["Engineers hear 'greatly' as 'unmeasured.'","Include the price: compute, latency, complexity — every gain has one.","A claim with a tradeoff attached sounds like experience."],"focus":["precision","audience"],"placeholder":"It cuts preprocessing errors by ~40% on noisy data, at the cost of —"},
    {"id":"precision-stu-senior-25","level":"senior","profession":"student","title":"The anecdote-to-evidence upgrade","scenario":"Arguing for a protocol change in lab meeting, you say 'the current method keeps failing.' You checked the lab notebook afterward: 5 failures in the last 20 runs, 4 of them on one instrument.","task":"Write the 2-sentence evidence-based version of your argument.","tips":["The count changes the conversation: 25% failure rate, concentrated on one machine.","The concentration detail points at the fix — that's the power of looking.","'Keeps failing' starts a debate; '5 of 20, 4 on instrument B' ends one."],"focus":["precision","impact"],"placeholder":"The method failed 5 of the last 20 runs — and 4 were on instrument B."}
  ],
  "executive-presence": [
    {"id":"presence-stu-senior-01","level":"senior","profession":"student","title":"The menu you keep serving","scenario":"Your advisor asks which analysis approach you should use, and as usual you present three options with balanced pros and cons, waiting for them to choose. You actually have a clear preference and the expertise to back it.","task":"Write a 2-3 sentence spoken recommendation that names your pick and defends it.","tips":["'I recommend A because —' is the sentence; options B and C are context.","You are the person who did the reading; own that.","Invite challenge after the recommendation, not instead of it."],"focus":["impact","clarity"],"placeholder":"I'd go with the mixed-effects approach, for two reasons."},
    {"id":"presence-stu-senior-02","level":"senior","profession":"student","title":"The signposted committee update","scenario":"Your committee meetings sprawl because you present without a map — members interrupt with questions you were about to answer. You have 20 minutes for this update.","task":"Write the opening 2-3 sentences that lay out the structure and take control of the time.","tips":["Announce the map: 'Three parts: results, the problem I hit, my proposed timeline.'","Tell them where questions fit: 'I'll pause after each part.'","A speaker with a visible plan gets interrupted less."],"focus":["structure","impact"]},
    {"id":"presence-stu-senior-03","level":"senior","profession":"student","title":"Fact and judgment, separated","scenario":"Presenting results to your lab, you say: 'The manipulation obviously didn't work because participants weren't paying attention.' Half of that is data; half is your guess — delivered at the same confidence.","task":"Rewrite the statement separating what the data show from what you infer.","tips":["Mark the boundary: 'The data show X. My interpretation is Y.'","Inference labeled as inference invites help; disguised as fact, it invites correction.","Your credibility compounds every time your labels turn out right."],"focus":["precision","clarity"],"placeholder":"The data show no effect of the manipulation. My read — and this part is interpretation —"},
    {"id":"presence-stu-senior-04","level":"senior","profession":"student","title":"The journal recommendation","scenario":"Your co-authors ask where to submit. You've compared scope, turnaround, and fit across four journals, but your draft email lists all four neutrally and asks 'thoughts?'","task":"Rewrite as a recommendation: your pick, two reasons, and the fallback.","tips":["Do the deciding you're equipped to do; senior co-authors can veto.","Name the fallback so a veto has somewhere to land.","'Thoughts?' generates threads; 'I recommend X, objections by Friday?' generates decisions."],"focus":["impact","structure"]},
    {"id":"presence-stu-senior-05","level":"senior","profession":"student","title":"Killing the failing experiment","scenario":"Experiment 3 has consumed four months and its design flaw is now clear to you. Your advisor hasn't given up on it. You want to recommend stopping — a call above your rank that your evidence supports.","task":"Write the 3-sentence spoken case for stopping, delivered as a recommendation rather than a complaint.","tips":["Lead with the recommendation, then the evidence, then the redirect.","Frame the cost forward: what four more weeks buys vs. what it costs.","Proposing what to do instead is what separates judgment from frustration."],"focus":["impact","precision"]},
    {"id":"presence-stu-senior-06","level":"senior","profession":"student","title":"The Q&A answer you own","scenario":"After your conference talk, someone asks which of two theories your data support. The honest answer involves nuance, but your instinct is to shrink: 'That's a great question, it's complicated, more research is needed.'","task":"Write a 2-3 sentence spoken answer that takes a position with its boundary.","tips":["Give the verdict with its scope: 'On this task, theory A — with one caveat.'","'More research is needed' is true of everything and says nothing.","A bounded position is defensible; a dodge is just memorable as a dodge."],"focus":["impact","precision"],"placeholder":"On this evidence, theory A — with one important boundary."},
    {"id":"presence-stu-senior-07","level":"senior","profession":"student","title":"The undergrad-hire recommendation","scenario":"Your PI asks whether the lab should take on the undergraduate you've been supervising for a paid position. You have real reservations and real praise. Your instinct is to hand your PI the raw pros and cons.","task":"Write a 2-3 sentence recommendation with a clear verdict and the key evidence.","tips":["The verdict first: hire, don't hire, or hire-with-conditions.","Your PI asked for your judgment, not your notes.","Name the condition that would flip your answer — that's completeness, not fence-sitting."],"focus":["impact","clarity"]},
    {"id":"presence-stu-senior-08","level":"senior","profession":"student","title":"The timeline you commit to","scenario":"Your committee asks if you can defend by May. The honest answer is yes-if. Your habit is to say 'hopefully, I mean, it depends' — which the committee hears as no.","task":"Write a one-sentence spoken commitment with its condition stated cleanly.","tips":["'Yes, if data collection closes by January' is ownership; 'hopefully' is weather.","State the condition once, precisely — not three hedges deep.","Then say what you're doing to secure the condition."],"focus":["impact","precision"],"placeholder":"Yes — May works if data collection closes by mid-January, and here's how I'm protecting that."},
    {"id":"presence-stu-senior-09","level":"senior","profession":"student","title":"The two-options memo with a pick","scenario":"You've scoped two designs for the next study and need your PI's decision. Your draft presents both symmetrically. Your PI has 90 seconds and would rather approve than analyze.","task":"Write a 4-5 sentence memo: recommendation first, then the comparison that supports it.","tips":["Recommendation, then reasons, then the runner-up's one advantage.","Make approving easy: 'Reply yes and I'll start Monday.'","Symmetric memos outsource the thinking you were asked to do."],"focus":["structure","impact"]},
    {"id":"presence-stu-senior-10","level":"senior","profession":"student","title":"The review you sign your judgment to","scenario":"You're writing your first solo peer review. Your draft lists ten observations without weights — the fatal flaw and the typo get equal billing, and your overall verdict hides in the middle.","task":"Write the review's opening paragraph: overall assessment, the decisive issue, and your recommendation.","tips":["Open with the verdict and its single strongest reason.","Rank your concerns: major, then minor, explicitly labeled.","The editor reads your first paragraph; the authors read all of it."],"focus":["structure","impact"]},
    {"id":"presence-stu-senior-11","level":"senior","profession":"student","title":"The conference-pick proposal","scenario":"The lab can fund one conference for you this year. You've compared three and know which serves your job-market year best. You're about to email your PI all three with costs, unranked.","task":"Write a 2-3 sentence proposal naming your choice and its strategic reason.","tips":["Lead with the pick and the career logic, then the cost.","Show you did the comparison in one clause, not one table.","Asking for a decision you could make yourself spends your PI's patience."],"focus":["impact","concision"]},
    {"id":"presence-stu-senior-12","level":"senior","profession":"student","title":"The authorship-order proposal","scenario":"The multi-lab paper is drafting its author list and no one wants to go first on the awkward question. You did the second-most work and believe the order should reflect it. Silence is about to decide for you.","task":"Write a 2-3 sentence message proposing a specific order with your rationale.","tips":["Propose the full order, not just your position — solve the whole problem.","Anchor to contributions, stated factually.","A concrete proposal gets edited; a raised concern gets deferred."],"focus":["impact","precision"]},
    {"id":"presence-stu-senior-13","level":"senior","profession":"student","title":"The teaching-change announcement","scenario":"Mid-semester, you're changing how your discussion sections run — less lecture recap, more problem-solving — based on the midterm results. You could apologize your way through the announcement, or lead it.","task":"Write the 2-3 sentence announcement to your students that owns the change.","tips":["State the change and the evidence-based reason, no apology.","'The midterm showed X, so we're doing Y' is leadership at TA scale.","Confidence in the room starts with confidence in the sentence."],"focus":["impact","audience"]},
    {"id":"presence-stu-senior-14","level":"senior","profession":"student","title":"The interdisciplinary meeting's voice","scenario":"In your joint-lab meetings, the other field's students speak in confident declaratives while you frame everything as questions — even your own results, which you know better than anyone in the room.","task":"Write the declarative spoken version of a finding you'd normally deliver as 'I was wondering if maybe —'.","tips":["State your result as the expert on it, which you are.","Save question-framing for actual questions.","You can be open to challenge and still speak in sentences."],"focus":["impact","clarity"]},
    {"id":"presence-stu-senior-15","level":"senior","profession":"student","title":"The signposted job talk","scenario":"Your job talk covers three studies and a research vision in 45 minutes. Faculty drift in and out; anyone arriving at minute 20 should still be able to locate themselves in your argument.","task":"Write the three transition sentences you'll use between the talk's major sections.","tips":["Each transition restates the throughline and locates the next section on it.","'So attention shapes encoding. The next question: does it shape retrieval too?'","Transitions are where talks are lost — script them word for word."],"focus":["structure","impact"]},
    {"id":"presence-stu-senior-16","level":"senior","profession":"student","title":"The tooling recommendation","scenario":"Your lab's analysis pipeline is held together by scripts only you understand, and you're graduating next year. You want the lab to adopt a proper workflow tool. This is your recommendation to make — you've felt the pain most.","task":"Write a 3-sentence pitch to the lab: the recommendation, the cost of the status quo, and the migration path.","tips":["Name the risk plainly: this knowledge leaves when I do.","Recommend one tool, not a survey of tools.","A migration path with hours attached turns a wish into a plan."],"focus":["impact","structure"]},
    {"id":"presence-stu-senior-17","level":"senior","profession":"student","title":"The confidence gradient","scenario":"Presenting to your committee, you have three claims: one you'd stake your degree on, one you believe, one you suspect. Your delivery flattens them to the same cautious mumble.","task":"Write the three claims as you'd speak them, with language that signals each confidence level.","tips":["Strong: 'The data clearly show.' Medium: 'The evidence points to.' Exploratory: 'One pattern worth testing —'","A visible gradient makes your strongest claims land harder.","Committees trust students who know what they know."],"focus":["precision","impact"]},
    {"id":"presence-stu-senior-18","level":"senior","profession":"student","title":"The design-choice defense","scenario":"A visiting professor questions why you used a between-subjects design. You chose it deliberately — carryover effects would have contaminated within-subjects data — but your instinct is to concede ground you shouldn't.","task":"Write the 2-sentence spoken defense that explains the choice without apologizing for it.","tips":["'I chose it because' beats 'we ended up with' — deliberate beats accidental.","Name the alternative and the specific reason you rejected it.","Conceding a real limitation later is easier from a position of owned choices."],"focus":["impact","precision"],"placeholder":"That was deliberate: carryover effects would have —"},
    {"id":"presence-stu-senior-19","level":"senior","profession":"student","title":"The journal-club stance","scenario":"You're presenting a flashy new paper at journal club. Your summary is thorough, but when someone asks 'so do you buy it?', you realize you prepared a book report, not a position.","task":"Write your 2-3 sentence verdict on the paper: what you buy, what you don't, and why.","tips":["A position on the evidence is the whole point of journal club.","Split your verdict: the finding may be solid while the interpretation overreaches.","'I buy the effect but not the mechanism' is a professional-grade sentence."],"focus":["impact","clarity"]},
    {"id":"presence-stu-senior-20","level":"senior","profession":"student","title":"The pivot announcement","scenario":"You've decided — with your advisor's blessing — to reframe your dissertation around the unexpected finding. Now you must tell your committee, some of whom championed the original framing. You could present it as drift, or as a decision.","task":"Write the 3-sentence announcement that frames the pivot as a reasoned decision.","tips":["Announce the decision, then the evidence that drove it, then what's preserved.","'The data took us somewhere better' is a story of strength.","Pre-empt the sunk-cost question: what happens to the completed work."],"focus":["impact","structure"],"placeholder":"We're reframing the dissertation around the retrieval finding — and the data made this decision for us."},
    {"id":"presence-stu-senior-21","level":"senior","profession":"student","title":"The reviewer-response strategy call","scenario":"Your co-authors are split on how to handle a demanding reviewer: run the requested experiment or argue it's out of scope. As first author, the call — and the case for it — is yours to make.","task":"Write a 3-sentence message to your co-authors stating your call and the reasoning.","tips":["Make the call, cost it out, and give the deciding factor.","'Running it costs six weeks; arguing risks rejection. I'd run it because —'","First authorship is a leadership role; this is what it looks like."],"focus":["impact","precision"]},
    {"id":"presence-stu-senior-22","level":"senior","profession":"student","title":"The seminar-question poise","scenario":"During your departmental talk, a senior professor asks a question that's half challenge, half misunderstanding of your slide 8. The room watches how you handle rank.","task":"Write the 2-3 sentence spoken reply that corrects the misunderstanding with respect and no retreat.","tips":["Honor the question's valid core before the correction.","Correct the record plainly: 'Slide 8 actually shows the control condition —'","Deference to rank should never extend to deference on facts you own."],"focus":["impact","audience"]},
    {"id":"presence-stu-senior-23","level":"senior","profession":"student","title":"The proactive scope defense","scenario":"Every committee meeting, someone suggests an additional study, and you've been saying 'great idea, I'll look into it' — your dissertation is now notionally seven studies. This meeting, you need a different sentence.","task":"Write the 2-sentence spoken response that protects your scope while respecting the suggestion.","tips":["'That's a strong post-defense direction' places the idea without adopting it.","Anchor to the agreed scope: 'The committee approved three studies; I want to finish those well.'","Guarding scope is a competence signal, not an insubordination."],"focus":["impact","clarity"],"placeholder":"I'd frame that as future work — here's why."},
    {"id":"presence-stu-senior-24","level":"senior","profession":"student","title":"The methods-workshop authority","scenario":"You're teaching a methods workshop where several attendees outrank you — postdocs, one professor. Your draft opening apologizes: 'You probably all know this better than me, but...'","task":"Write the opening 2 sentences that establish why you're the right person teaching this.","tips":["Anchor authority to specifics: 'I've run this pipeline 200 times and broken it every way it breaks.'","Rank and expertise are different axes — you're high on the one that matters today.","Never open with an apology for existing at the podium."],"focus":["impact","audience"],"placeholder":"I've run this pipeline about 200 times, and today I'll save you my worst 20 hours."},
    {"id":"presence-stu-senior-25","level":"senior","profession":"student","title":"The 'what do YOU think?' moment","scenario":"After you present two interpretations of your data to your committee, a member cuts through: 'You've told us what it could mean. What do you think it means?' The room waits.","task":"Write the 2-3 sentence spoken answer that finally commits.","tips":["Commit to one interpretation and give your best single reason.","Acknowledge the rival view in a clause, not a paragraph.","This question is a gift: they're asking you to be a colleague."],"focus":["impact","clarity"],"placeholder":"I think it's the encoding account, and here's what convinces me."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-stu-senior-01","level":"senior","profession":"student","title":"The question you didn't get asked","scenario":"At your defense, a committee member asks: 'Why should we believe this generalizes beyond your sample?' You launch into your favorite explanation of the sample's strengths — which is the answer to a different question.","task":"Write a 2-3 sentence spoken answer that addresses generalization directly, first.","tips":["Answer the asked question in sentence one, even if a nearby question suits you better.","'It generalizes to X but I can't claim Y' is a direct answer.","Committees repeat unanswered questions louder."],"focus":["clarity","precision"],"placeholder":"Honestly, it generalizes to young adults in laboratory settings — beyond that, I'd be speculating."},
    {"id":"pressure-stu-senior-02","level":"senior","profession":"student","title":"The hostile conference question","scenario":"After your talk, a researcher whose theory your data undermine stands up: 'Isn't your entire paradigm just measuring task demand, not the effect you claim?' The room goes quiet. You anticipated this exact objection — you ran a control for it.","task":"Write the 2-3 sentence spoken answer that meets the challenge with the control data.","tips":["Steady tone, specific evidence: 'We tested that — the demand control showed no effect.'","Don't match hostility; outclass it with data.","End by conceding what the control can't rule out — precision defuses."],"focus":["precision","impact"],"placeholder":"We worried about that too, so we ran a demand control —"},
    {"id":"pressure-stu-senior-03","level":"senior","profession":"student","title":"The honest 'I don't know' in quals","scenario":"Your qualifying exam. An examiner asks about a literature you haven't read. Bluffing in front of people who wrote that literature is a documented way to fail.","task":"Write the spoken answer that admits the gap and shows how you'd close it.","tips":["Say it cleanly: 'I don't know that literature well enough to answer responsibly.'","Then reason from what you do know: 'From first principles, I'd expect —'","Examiners test the edge of knowledge; how you behave at the edge is the exam."],"focus":["clarity","impact"],"placeholder":"I haven't read that literature deeply enough to answer well. Reasoning from what I do know —"},
    {"id":"pressure-stu-senior-04","level":"senior","profession":"student","title":"The advisor's pushback","scenario":"You proposed dropping a study; your advisor pushes back hard: 'We committed to this in the grant.' They're not wrong about the commitment — but the study as designed cannot answer the grant's question, and you can show why.","task":"Write the 2-3 sentence spoken response that engages the grant concern with specifics.","tips":["Start inside their frame: the grant's actual aim, quoted.","Show the mismatch: the study as designed can't deliver that aim.","Propose the version that could — pushback plus alternative equals dialogue."],"focus":["precision","structure"]},
    {"id":"pressure-stu-senior-05","level":"senior","profession":"student","title":"Reviewer 2, answered without heat","scenario":"The review is contemptuous: 'The authors seem unaware of basic psychometrics.' Your first-draft response is contemptuous back. The editor will read both, and only one of you is asking for something.","task":"Write the 2-3 sentence response that answers the substance and drops the heat.","tips":["Extract the reviewable claim from the insult and answer only that.","'We now report reliability coefficients in Table 2' wins; sarcasm loses.","The editor is your audience; the reviewer is just the prompt."],"focus":["precision","audience"]},
    {"id":"pressure-stu-senior-06","level":"senior","profession":"student","title":"The stats ambush","scenario":"Mid-presentation, a professor asks why you didn't use a Bayesian approach. You considered it, chose frequentist methods for pre-registration comparability, and haven't thought about the choice in a year.","task":"Write the 2-sentence spoken answer that retrieves your reasoning under pressure.","tips":["Buy a beat: 'Good question — we did consider it.' Then the reason.","One real reason beats three reconstructed ones.","Offer the follow-up: 'Happy to go deeper on the tradeoff after.'"],"focus":["clarity","precision"]},
    {"id":"pressure-stu-senior-07","level":"senior","profession":"student","title":"The 'why does this matter?' committee question","scenario":"Deep in your methods presentation, a committee member leans back: 'Step back — why does any of this matter?' It's not hostile; it's a zoom-out you weren't ready for at minute 40.","task":"Write the 2-3 sentence spoken answer that climbs from your methods to the stakes.","tips":["Climb the ladder fast: finding → field implication → real-world stake.","Have this answer pre-built; every project needs its 'why' cached.","Passion helps here — this is the one answer where feeling is evidence."],"focus":["impact","audience"]},
    {"id":"pressure-stu-senior-08","level":"senior","profession":"student","title":"The grade dispute","scenario":"A student in your section, composed but angry, argues their exam answer deserves the points: 'You marked the same answer right for my friend.' You need to respond now, in office hours, without seeing the friend's paper.","task":"Write the 2-3 sentence spoken response that is fair, specific, and doesn't fold under pressure.","tips":["Address their actual paper first: what the rubric required, what theirs shows.","Commit to checking the consistency claim — specifically and by when.","Fair process, stated calmly, is the answer; instant capitulation isn't."],"focus":["clarity","audience"]},
    {"id":"pressure-stu-senior-09","level":"senior","profession":"student","title":"The failed-project interview question","scenario":"An industry interviewer asks: 'Tell me about a research project that failed.' You have a spectacular one — a year on an effect that turned out to be an artifact. The trap is narrating it as either tragedy or shrug.","task":"Write a 3-4 sentence spoken answer: the failure, the diagnosis, and what it changed in how you work.","tips":["Name the failure plainly — evasion reads worse than failure.","The diagnosis is the showcase: how you found the artifact.","End with the changed behavior: what you now do differently, permanently."],"focus":["structure","impact"],"placeholder":"I spent a year on an effect that turned out to be an artifact of the stimulus set."},
    {"id":"pressure-stu-senior-10","level":"senior","profession":"student","title":"The 'hasn't this been done?' question","scenario":"At your poster, a professor squints: 'Didn't Tanaka's lab do exactly this in 2019?' You know Tanaka's study — it's your closest neighbor and differs in the one way that matters.","task":"Write the 2-sentence spoken answer that locates your contribution against the prior work.","tips":["Credit the prior work precisely — it proves you know the terrain.","Name the one difference and why it changes the conclusion.","'Same question, different answer, because —' is the shape."],"focus":["precision","clarity"]},
    {"id":"pressure-stu-senior-11","level":"senior","profession":"student","title":"The question outside your chapter","scenario":"At your defense, a committee member asks about a literature adjacent to your dissertation — relevant, but outside what you wrote. You know it at journal-club depth, not chapter depth.","task":"Write the spoken answer that gives your real depth honestly and connects it back to your work.","tips":["Scope your answer honestly: 'At the level I know that work —'","Bridge to your ground: connect their question to what you can defend.","Never let a question pull you into defending territory you don't hold."],"focus":["clarity","precision"]},
    {"id":"pressure-stu-senior-12","level":"senior","profession":"student","title":"The 'why are you behind?' meeting","scenario":"Your advisor opens the meeting with: 'You said the analysis would be done two weeks ago. What's going on?' The true answer involves a data problem, a TA crunch, and some avoidance you're not proud of.","task":"Write the 2-3 sentence spoken answer that takes ownership and gets to the plan.","tips":["No excuse cascade — one honest sentence of cause.","Ownership sounds like: 'I misjudged the data cleaning, and I let it slide during grading.'","Spend the rest on the recovery plan with a date."],"focus":["clarity","impact"],"placeholder":"Two things, honestly: the data cleaning was worse than I scoped, and I let grading eat the buffer. Here's the recovery plan."},
    {"id":"pressure-stu-senior-13","level":"senior","profession":"student","title":"The limitation you hoped they'd miss","scenario":"The funding panel found it: 'Your design can't separate practice effects from the intervention, can it?' They're right. You knew; you'd hoped. Now the only good move is the honest one, made well.","task":"Write the 2-3 sentence spoken answer that concedes the confound and contains it.","tips":["Concede immediately and precisely — the panel already knows.","Contain it: what the design CAN show despite the confound.","Offer the fix: the follow-up design that separates them."],"focus":["precision","impact"],"placeholder":"You're right — this design can't separate them. What it can show is —"},
    {"id":"pressure-stu-senior-14","level":"senior","profession":"student","title":"The dead demo","scenario":"Your live analysis demo just crashed in front of the visiting collaborators. Thirty seconds of silence while you retry would be worse than anything you could say. You have result slides as backup.","task":"Write the 1-2 sentences you say in the moment to keep the room and move forward.","tips":["Name it lightly, move immediately: no fumbling apology spiral.","'The demo gods have spoken — here are the results it would have shown.'","Composure under a broken demo is itself a demonstration."],"focus":["impact","concision"]},
    {"id":"pressure-stu-senior-15","level":"senior","profession":"student","title":"The 'what would you do differently?' question","scenario":"Your defense is going well, and then: 'Knowing everything you know now, how would you redo this dissertation?' A soft-sounding question with teeth — too little candor looks arrogant, too much unravels your own work.","task":"Write the 2-3 sentence spoken answer that shows judgment without undermining the thesis.","tips":["Pick one real, specific change — the one you'd actually make.","Explain why the work stands anyway: the change sharpens, not saves.","This question grades your growth, not your regret."],"focus":["clarity","impact"]},
    {"id":"pressure-stu-senior-16","level":"senior","profession":"student","title":"The journalist's oversimplification","scenario":"A reporter interviewing you about your paper says: 'So basically, your study proves screens are destroying kids' memory?' Saying 'no' loses them; saying 'yes' becomes a headline you'll spend a year living down.","task":"Write the 1-2 sentence spoken answer that corrects the claim while staying quotable.","tips":["Give them a better quote, not a lecture: correct by replacement.","Keep the accurate version vivid — dullness is why they oversimplify.","Practice these before the call; live correction is a skill."],"focus":["precision","audience"],"placeholder":"Not destroying — but we found one specific cost:"},
    {"id":"pressure-stu-senior-17","level":"senior","profession":"student","title":"The interruption you talk through","scenario":"Two minutes into your committee-meeting answer, a professor interrupts with a new question. Abandoning the first answer loses the point you were building; ignoring the interruption is not survivable politics.","task":"Write the 1-2 sentence spoken bridge that handles the interruption and closes the original point.","tips":["Acknowledge, park, and finish: 'I'll come to that — one sentence to close the first point.'","Then actually come to it; a broken promise here costs double.","Owning the floor politely is a skill committees respect."],"focus":["structure","impact"]},
    {"id":"pressure-stu-senior-18","level":"senior","profession":"student","title":"The sample-size skeptic","scenario":"A workshop audience member challenges you: 'n of 40? How is that publishable?' Your power analysis says otherwise, and the effect is within-subjects with 1,200 trials each — but the question sounded devastating to the room.","task":"Write the 2-sentence spoken answer that re-educates the room without condescending to the asker.","tips":["Answer to the room's takeaway: trials, not just heads, drive power here.","'40 people, 1,200 trials each — the power analysis is in the appendix.'","Respect in tone, firmness in fact."],"focus":["precision","audience"]},
    {"id":"pressure-stu-senior-19","level":"senior","profession":"student","title":"The 'so what can you do for us?' interview","scenario":"The hiring manager at a tech company, unimpressed by titles: 'A PhD in cognitive science. What does that actually do for my team?' Your answer needs to land in their world, in under thirty seconds.","task":"Write the 2-3 sentence spoken answer that converts your training into their outcomes.","tips":["Their language: experiments that de-risk product decisions, models that predict behavior.","One concrete example of a skill applied outside academia.","Confidence without defensiveness — the question is fair."],"focus":["audience","impact"],"placeholder":"Three things, concretely: I design experiments that give you answers instead of opinions —"},
    {"id":"pressure-stu-senior-20","level":"senior","profession":"student","title":"The two-part question","scenario":"A defense examiner asks a compound question: part one about your stimuli, part two about your model's assumptions. Under pressure, you'll instinctively answer the easier half and hope.","task":"Write the spoken answer's opening that structures both parts before answering either.","tips":["Split it out loud: 'Two questions there — stimuli, then assumptions. Stimuli first.'","Naming the structure buys thinking time legitimately.","Answer both; examiners keep score."],"focus":["structure","clarity"]},
    {"id":"pressure-stu-senior-21","level":"senior","profession":"student","title":"The question you already answered","scenario":"Late in your talk's Q&A, someone asks — with confidence — a question your slide 6 explicitly addressed. Half the room remembers; the asker doesn't. Humiliation and evasion are both wrong.","task":"Write the 1-2 sentence spoken answer that re-covers the ground gracefully.","tips":["Answer fresh, don't cite the slide: 'Right — the short version is X.'","'As I said' scores a point and loses the room.","Maybe your slide 6 was less clear than you thought — hold that possibility."],"focus":["audience","concision"]},
    {"id":"pressure-stu-senior-22","level":"senior","profession":"student","title":"Caught between two committee members","scenario":"In your committee meeting, Professor A says your sample must be bigger; Professor B says your timeline can't absorb more collection. They look at you: 'Which is it?' Their conflict has just become your question.","task":"Write the 2-3 sentence spoken response that addresses the tradeoff without taking casualties.","tips":["Name the tradeoff as a tradeoff — that reframes it from loyalty test to design question.","Bring data: what the power analysis says the sample buys.","Propose the resolution and let the committee own the final call."],"focus":["structure","impact"]},
    {"id":"pressure-stu-senior-23","level":"senior","profession":"student","title":"The 'have you considered' you haven't","scenario":"A seminar audience member asks whether you've considered an alternative explanation — one that genuinely never occurred to you and, in the ten seconds you've had it, sounds plausible.","task":"Write the spoken answer that takes the idea seriously in real time without collapsing.","tips":["'I haven't — and it's interesting' costs nothing and buys credibility.","Think aloud briefly: which of your data could already test it?","Get their name after; live-generated alternatives are collaborations waiting."],"focus":["clarity","impact"],"placeholder":"I haven't, honestly — and off the top of my head, our condition B data might already speak to it."},
    {"id":"pressure-stu-senior-24","level":"senior","profession":"student","title":"The 'your method is flawed' broadside","scenario":"A senior researcher at a workshop declares your method 'fundamentally flawed' because it relies on self-report. It's a known limitation with known defenses, and your convergent behavioral measure agrees with the self-report data.","task":"Write the 2-3 sentence spoken answer that converts the broadside into a specific, answerable claim.","tips":["Narrow it first: 'The concern is self-report bias, specifically.'","Then the convergence: the behavioral measure tells the same story.","Broad attacks die by specificity — yours, not theirs."],"focus":["precision","structure"]},
    {"id":"pressure-stu-senior-25","level":"senior","profession":"student","title":"The defense's final question","scenario":"End of your defense. The chair asks the traditional closer: 'What's the one thing you want us to remember about this work?' Two hours of questions have scattered your framing; now you get one sentence to gather it.","task":"Write the 1-2 sentence spoken answer that plants your dissertation's flag.","tips":["One claim, planted firmly — not a summary of chapters.","Prepare this sentence before the defense; it should never be improvised.","It's the sentence they'll repeat when they describe your work to others."],"focus":["impact","concision"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-stu-senior-01","level":"senior","profession":"student","title":"The fellowship's opening story","scenario":"Your fellowship personal statement opens with 'I am applying for this fellowship because...' — the same first line as most of the pile. Your actual origin story involves a specific patient your undergrad lab studied, whose case still drives your question.","task":"Write the 2-3 sentence opening that earns the reader's next paragraph.","tips":["Open inside the specific: a case, a moment, a number that started it.","The story must aim at your research question, not just decorate it.","Cut anything that could appear in someone else's statement."],"focus":["impact","audience"]},
    {"id":"narrative-stu-senior-02","level":"senior","profession":"student","title":"The paper intro as story","scenario":"Your intro states facts in sequence but has no tension — nothing is at stake, nothing needs resolving. The actual situation is dramatic: two respected theories predict opposite results in your paradigm.","task":"Write the 3-sentence version of the intro that stages the conflict your study resolves.","tips":["Set the collision: theory A predicts up, theory B predicts down.","The stakes: whoever is right, textbooks change a sentence.","Your study enters as the arbiter — that's the narrative slot it wants."],"focus":["structure","impact"],"placeholder":"Two well-supported theories make opposite predictions here."},
    {"id":"narrative-stu-senior-03","level":"senior","profession":"student","title":"The side-project pitch","scenario":"You want your advisor's blessing for a side project: a small study spinning off your main data. Advisors hear 'side project' as 'distraction from finishing.' Your case needs to defuse exactly that.","task":"Write the 3-4 sentence pitch that pre-empts the distraction objection.","tips":["Raise their objection before they do: 'The obvious worry is timeline —'","Bound it: the hours, the end date, the kill criterion.","Frame the payoff in their currency: a paper, a grant angle, your job market."],"focus":["impact","structure"],"placeholder":"I want to propose a bounded side project — and let me address the timeline worry first."},
    {"id":"narrative-stu-senior-04","level":"senior","profession":"student","title":"Stakes the panel can feel","scenario":"Your grant application says the research 'addresses an important gap in the literature.' Every application says that. The real stakes: misdiagnosis rates in the population you study, and a screening tool your findings could recalibrate.","task":"Rewrite the significance sentence with stakes a reviewer can picture.","tips":["Gaps are cartography; stakes are people. Write the people.","One concrete consequence: who is affected, how often, what changes.","The reviewer should finish the sentence able to defend your grant to a colleague."],"focus":["impact","precision"],"placeholder":"One in five of these screenings currently returns the wrong answer —"},
    {"id":"narrative-stu-senior-05","level":"senior","profession":"student","title":"The strongest objection, pre-empted","scenario":"Your proposal's weak point is obvious to anyone senior: your timeline assumes recruitment rates nobody achieves. You could hope the committee misses it. They will not miss it.","task":"Write the 2-3 sentence passage that raises and answers the objection before they do.","tips":["Name it plainly: 'The recruitment assumption deserves scrutiny.'","Then the mitigation: the backup site, the pilot rate data, the trigger for plan B.","Owning the weakness converts it from ambush to evidence of judgment."],"focus":["impact","precision"]},
    {"id":"narrative-stu-senior-06","level":"senior","profession":"student","title":"The job talk's arc","scenario":"Your job talk currently presents three studies as three episodes. A search committee remembers arcs, not episodes: where the field was, what you changed, where you'll take it.","task":"Write the one-sentence before, after, and next-chapter of your research story.","tips":["Before: what the field believed. After: what your work made untenable.","The 'next chapter' sentence is what they're hiring — make it vivid.","Every study in the talk should be a beat in this arc or be cut."],"focus":["structure","impact"],"placeholder":"Five years ago, the field assumed X. My work shows —"},
    {"id":"narrative-stu-senior-07","level":"senior","profession":"student","title":"The protocol-change persuasion","scenario":"You want the lab to adopt pre-registration for all new studies. The senior grad students see paperwork; the PI sees friction. You see the replication crisis and a lab whose findings you want to age well.","task":"Write the 3-4 sentence pitch for lab meeting that moves the skeptics.","tips":["Frame from their seat: what each skeptic loses now vs. gains later.","One story lands harder than statistics: name a famous unreplicated finding in your area.","Shrink the ask: pilot it on one study, revisit in three months."],"focus":["impact","audience"]},
    {"id":"narrative-stu-senior-08","level":"senior","profession":"student","title":"The committee invitation that persuades","scenario":"The professor you want on your committee is oversubscribed and says no to most students. Your draft email lists your project's features. Her decision will hinge on whether the project interests her — a story problem, not a feature problem.","task":"Write the 2-3 sentence pitch framed around what makes the project interesting to her work.","tips":["Hook to her open question: your data speak to something she's written about.","Scarcity of commitment: name the small, bounded role you're asking for.","Make the intellectual payoff hers, not just yours."],"focus":["audience","impact"]},
    {"id":"narrative-stu-senior-09","level":"senior","profession":"student","title":"The three-minute-thesis narrative","scenario":"Your three-minute-thesis draft is a compressed lecture. The winning entries you've watched are stories: a character (sometimes the researcher, sometimes a cell), a problem, a turn, a resolution that lands on the research.","task":"Write the 4-beat story outline of your thesis: character, problem, turn, resolution.","tips":["Pick the character the audience can inhabit — a patient, a student, a neuron.","The 'turn' is your insight arriving in the story's world.","Rehearse the resolution sentence hardest; it carries the applause."],"focus":["structure","audience"]},
    {"id":"narrative-stu-senior-10","level":"senior","profession":"student","title":"The industry pivot letter","scenario":"Your cover letter for a UX research role reads as an apology for leaving academia. The true story is better: five years learning to extract signal from human behavior, now aimed at products people use.","task":"Write the 2-3 sentence cover letter opening that frames the pivot as trajectory, not retreat.","tips":["Continuity, not conversion: the same skill, a new arena.","Lead with what you bring, not what you're leaving.","One sentence should preview a concrete skill-to-role match."],"focus":["impact","audience"],"placeholder":"I've spent five years learning how people actually behave — not how they say they behave."},
    {"id":"narrative-stu-senior-11","level":"senior","profession":"student","title":"The data-sharing persuasion","scenario":"A researcher at another university holds the comparison dataset your chapter needs. Sharing costs them effort and yields them little — unless you shape the exchange so it doesn't.","task":"Write the 3-sentence request that makes sharing worth their while.","tips":["Lead with what they get: co-authorship, a citation, your cleaned harmonization of their data.","Shrink the burden: name exactly which files, offer your own data-use agreement draft.","A specific, low-effort, mutually credited ask is hard to refuse."],"focus":["audience","impact"]},
    {"id":"narrative-stu-senior-12","level":"senior","profession":"student","title":"The null result reframed","scenario":"Your registered study found nothing — a clean, well-powered null. Your draft presents it as a failure with apologies. A well-powered null in this literature kills a popular intervention claim, which is a contribution.","task":"Write the 2-3 sentence framing that presents the null as the finding it is.","tips":["A confident null is a result: 'The intervention does not produce the claimed effect.'","Stakes: who spends money on this intervention today?","Apologetic framing invites rejection; evidentiary framing invites citation."],"focus":["impact","precision"],"placeholder":"With 95% power, we find no effect — the intervention's central claim does not survive."},
    {"id":"narrative-stu-senior-13","level":"senior","profession":"student","title":"The travel-funding story","scenario":"The department's travel-grant committee reads fifty identical requests: 'presenting my research at a major conference.' Your actual situation has a story — this conference hosts the three labs you want a postdoc in, and your talk slot is in their symposium.","task":"Write the 2-3 sentence justification that makes your request the memorable one.","tips":["The career-moment frame: this specific conference, this specific year, because —","Name the concrete opportunity: the symposium, the labs, the timing.","Committees fund turning points more readily than routines."],"focus":["impact","precision"]},
    {"id":"narrative-stu-senior-14","level":"senior","profession":"student","title":"The recruitment pitch with a why","scenario":"You need undergraduates to join your study as research assistants for credit. Your posting lists tasks: coding videos, running participants. The students you want are choosing between labs, and tasks don't choose labs — trajectories do.","task":"Write the 3-sentence posting that sells the experience, honestly.","tips":["Lead with what they'll learn and touch: real data, a possible poster, a letter that says specifics.","Name a past RA's outcome — your lab's track record is the proof.","Honest tasks plus real growth beats inflated glamour."],"focus":["audience","impact"]},
    {"id":"narrative-stu-senior-15","level":"senior","profession":"student","title":"The authorship case","scenario":"You believe your contribution to the collaboration merits second authorship; the current draft order has you fourth. You need to persuade your advisor to advocate for you — with a case, not a complaint.","task":"Write the 3-sentence case: your contributions, the criterion, and the specific ask.","tips":["Argue from the criterion, not the feeling: contribution categories, hours, sections written.","Make the ask actionable: 'I'd like you to raise moving me to second.'","Anticipate the counter: who else claims that slot, and why your case holds."],"focus":["precision","impact"]},
    {"id":"narrative-stu-senior-16","level":"senior","profession":"student","title":"The gap-year framing","scenario":"Your CV has an eighteen-month gap between undergrad and grad school. In interviews you rush past it apologetically. In fact you spent it caregiving for a parent — and running the family's small business, which taught you more operations than any course.","task":"Write the 2-3 sentence spoken framing of the gap that turns it into evidence.","tips":["Own it at normal speed — rushing signals shame where none belongs.","Extract the transferable: what the period built that the lab now uses.","You control the frame; interviewers mostly adopt the frame they're handed."],"focus":["impact","clarity"]},
    {"id":"narrative-stu-senior-17","level":"senior","profession":"student","title":"The editor appeal","scenario":"Your paper was rejected after review, but one reviewer misread the design and their error anchored the decision. An appeal is a persuasion problem with an audience of one busy editor who has already said no once.","task":"Write the 3-sentence core of the appeal: the specific error, its role in the decision, and your bounded ask.","tips":["Surgical, not aggrieved: one error, documented, decision-relevant.","Concede everything else — appeals that re-litigate all comments lose.","Ask for the minimum: a re-review by a reader without the misreading."],"focus":["precision","structure"]},
    {"id":"narrative-stu-senior-18","level":"senior","profession":"student","title":"The seminar hook","scenario":"Your departmental seminar starts at 4pm — the audience arrives tired, and your first slide currently reads 'Outline.' You have one true fact that stops people: participants in your study confidently remembered an event that never happened, eleven times out of twenty.","task":"Write the opening 2 sentences that use the hook to open the whole talk.","tips":["Lead with the arresting fact, then let the question it raises structure everything.","An 'Outline' slide at 4pm is a lullaby.","The hook must be load-bearing — it should be the talk in miniature."],"focus":["impact","audience"],"placeholder":"Eleven of twenty participants vividly remembered an event that never happened."},
    {"id":"narrative-stu-senior-19","level":"senior","profession":"student","title":"The equipment case","scenario":"You want the lab to buy a $12,000 eye tracker. Your PI's grant could cover it, but every purchase competes with a conference trip or an RA's hours. The case must be about the lab's science, not your convenience.","task":"Write the 3-4 sentence proposal that makes the purchase a lab-level investment.","tips":["Count the beneficiaries: three current projects and every future attention study.","Cost per study over five years reframes the sticker price.","Name the alternative and its hidden cost: renting time across town at $200/session."],"focus":["impact","precision"]},
    {"id":"narrative-stu-senior-20","level":"senior","profession":"student","title":"The donor tour stop","scenario":"University donors are touring your lab for six minutes, and your PI asked you to present your station. Donors fund futures they can picture — not methods they can't. Your eye-tracking rig has an obvious human story.","task":"Write the 2-3 sentence station pitch for a donor audience.","tips":["Start with the person your work could someday help.","Let them try or see one vivid thing — the pitch frames it.","End with trajectory: 'with support, this goes from lab demo to classroom tool.'"],"focus":["audience","impact"]},
    {"id":"narrative-stu-senior-21","level":"senior","profession":"student","title":"The first-lecture why","scenario":"You're guest-lecturing on your specialty to 200 second-years who need this course but not, as far as they know, this topic. Your opening must answer the question they won't ask aloud: why should I care?","task":"Write the 2-3 sentence opening that connects your topic to their lives before any content.","tips":["Start in their world: a decision, an app, a habit your topic secretly runs.","Delay terminology until the care is established.","One rhetorical question can carry a lecture hall if it's genuinely theirs."],"focus":["audience","impact"]},
    {"id":"narrative-stu-senior-22","level":"senior","profession":"student","title":"The interdisciplinary risk, reframed","scenario":"A fellowship interviewer notes your project 'falls between two fields' — the polite version of 'no field will claim it.' The same fact is your strongest asset: the question is invisible from inside either field alone.","task":"Write the 2-sentence spoken reframe that turns between-ness into the project's edge.","tips":["Accept the premise, invert the valence: between fields is where this question lives.","Evidence: name the finding neither field could have produced alone.","Deliver it as an advantage you chose, not a location you fell into."],"focus":["impact","clarity"],"placeholder":"It does fall between them — deliberately. This question is invisible from inside either field."},
    {"id":"narrative-stu-senior-23","level":"senior","profession":"student","title":"The external-internship case","scenario":"You want your program's approval for a summer industry internship. The program director's default: internships delay degrees. Your case: the internship's dataset becomes chapter 5, and the company's letter confirms data access.","task":"Write the 3-sentence request that pre-empts the delay objection with the chapter plan.","tips":["Lead with the degree-serving frame: this internship produces a chapter.","Evidence over assurance: the confirmed dataset, the co-supervision agreement.","Give the director the sentence they need for their own approval chain."],"focus":["impact","structure"]},
    {"id":"narrative-stu-senior-24","level":"senior","profession":"student","title":"The teaching-philosophy story","scenario":"Your teaching statement claims you believe in 'active learning.' So does every statement in the stack. What you actually have is a story: the semester you replaced recap sections with problem-solving and watched the failing third of the class close the gap.","task":"Write the 3-4 sentence version where the story carries the philosophy.","tips":["The belief earns its place only as the story's conclusion.","Numbers inside stories: the failing third, the closed gap.","Committees skim claims and remember scenes."],"focus":["impact","structure"]},
    {"id":"narrative-stu-senior-25","level":"senior","profession":"student","title":"The skeptical mentor and your timeline","scenario":"Your secondary mentor thinks your plan to defend in twelve months is fantasy and says so. Persuading her matters — she writes one of your letters. Your case: the remaining work is analysis and writing, the data are in hand, and you have a chapter-per-month record to point to.","task":"Write the 3-sentence spoken case that converts her skepticism with evidence.","tips":["Meet skepticism with base rates: your own demonstrated pace, not aspiration.","Decompose the remaining work — fantasy lives in vagueness.","Invite her monitoring: milestone check-ins convert a skeptic into a witness."],"focus":["precision","impact"],"placeholder":"Twelve months is tight but evidenced — the data are in hand, and here's my chapter pace so far."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-stu-senior-01","level":"senior","profession":"student","title":"The failed experiment, told straight","scenario":"Six weeks of data collection are unusable — a counterbalancing error in your experiment script, your error. Your advisor meets you in an hour. The draft in your head keeps softening the word 'unusable.'","task":"Write the 2-3 sentence spoken opening that delivers the news without cushioning it into ambiguity.","tips":["Front-load: the data are unusable, the cause was my script error.","Vagueness here would force your advisor to interrogate the bad news out of you.","Arrive with the recovery plan — that's the second half of the message, not a separate meeting."],"focus":["clarity","impact"],"placeholder":"I have bad news: the six weeks of data are unusable, and the error was mine."},
    {"id":"hard-stu-senior-02","level":"senior","profession":"student","title":"The clean no to extra TA work","scenario":"The course coordinator asks you to take a second TA section this term 'because you're so good with the students.' You're protecting your final data-collection push. Yes would be easier for everyone but you.","task":"Write the 2-3 sentence reply that declines clearly without a fog of maybe.","tips":["A clean no names the reason once and doesn't relitigate: 'I can't this term — I'm in final data collection.'","Don't offer a fake maybe to soften it; retracted maybes cost more.","Offering a smaller alternative is optional, not owed."],"focus":["clarity","concision"],"placeholder":"I can't take a second section this term — I'm protecting my final data collection."},
    {"id":"hard-stu-senior-03","level":"senior","profession":"student","title":"The collaborator's data error","scenario":"Reviewing your collaborator's contributed dataset, you found a coding error that invalidates one of their reported measures — one they've already published on elsewhere. They're senior to you. The email is unavoidable.","task":"Write the 3-sentence email opening: the finding, the evidence, and the neutral next step.","tips":["Report the observation, not the accusation: 'Column 12 appears to code the reverse of the codebook.'","Attach the evidence so verification is one click.","Propose a call — tone survives calls better than threads."],"focus":["precision","audience"]},
    {"id":"hard-stu-senior-04","level":"senior","profession":"student","title":"The six-month slip","scenario":"Your committee expects a spring defense. Data problems have made that impossible — fall is realistic. Your draft email opens with three paragraphs of context, hoping the delay will feel inevitable by the time it's mentioned.","task":"Write the 2-3 sentence version that leads with the slip and the new date.","tips":["The delay is the message: say it in sentence one with the new date.","One sentence of cause, not a defense brief.","Include what the slip does NOT affect — funding, the completed studies — to size it accurately."],"focus":["clarity","structure"]},
    {"id":"hard-stu-senior-05","level":"senior","profession":"student","title":"The labmate's shared-code problem","scenario":"A labmate's uncommented, hard-coded scripts broke everyone's analyses twice this month. You use the shared pipeline most, so the lab is looking at you to raise it. The labmate is defensive by temperament.","task":"Write the behavior-impact-ask message you'd send them directly.","tips":["Behavior, observed: 'The last two pushes had hard-coded paths.' Not: 'Your code is sloppy.'","Impact, concrete: whose runs broke, how many hours lost.","Ask, specific: relative paths and a one-line comment per function — not 'be more careful.'"],"focus":["clarity","precision"]},
    {"id":"hard-stu-senior-06","level":"senior","profession":"student","title":"Declining the co-authorship request","scenario":"A friend in your program asks you to join their paper as a co-author for 'some stats help' — an hour of work for an authorship. It's flattering, generous, and against the contribution standards you take seriously.","task":"Write the 2-3 sentence reply that declines the authorship while keeping the friend.","tips":["Separate the help from the credit: yes to the hour, no to the byline.","Name the principle once, without preaching.","Suggest the acknowledgments line as the accurate home for it."],"focus":["clarity","audience"]},
    {"id":"hard-stu-senior-07","level":"senior","profession":"student","title":"The mentee's not-ready draft","scenario":"Your undergraduate mentee submitted their honors thesis draft to you, visibly proud. It is not ready — the analysis is wrong and two sections are missing. The defense is in five weeks, which is enough time only if they hear the truth today.","task":"Write the 3-4 sentence feedback opening that is honest about the state and concrete about the path.","tips":["Kindness here is clarity: 'This isn't ready yet, and five weeks is enough to fix it.'","Lead with the biggest problem, not a softening tour of the good parts.","End with the ordered fix list — hope needs a route."],"focus":["clarity","impact"],"placeholder":"The honest read: this isn't ready yet — and five weeks is enough if we fix things in this order."},
    {"id":"hard-stu-senior-08","level":"senior","profession":"student","title":"Leaving the collaboration","scenario":"The three-lab side collaboration you joined has doubled in scope while your dissertation deadline hasn't moved. You need to withdraw. Your work so far is in the shared repo; your exit shouldn't strand anyone.","task":"Write the 3-sentence withdrawal message: the decision, the reason, and the handoff.","tips":["State the withdrawal as decided, not as a question to be talked out of.","One reason, honestly sized: the dissertation timeline.","The handoff is the respect: what's documented, who you'll brief, by when."],"focus":["clarity","structure"]},
    {"id":"hard-stu-senior-09","level":"senior","profession":"student","title":"The disagreement with your advisor's interpretation","scenario":"Your advisor reads the interaction effect as supporting their long-standing theory. You think it's a floor effect — and you have the distribution plots. Their name is on the paper; so is yours.","task":"Write the 2-3 sentence spoken opening that states your disagreement with its evidence.","tips":["Direct and specific beats deferential and vague: 'I read this differently — I think it's a floor effect.'","Point to the plot, not to your feelings about the theory.","Propose the analysis that would settle it — disagreements should end in tests."],"focus":["clarity","precision"],"placeholder":"I read this result differently, and I want to show you why."},
    {"id":"hard-stu-senior-10","level":"senior","profession":"student","title":"The industry conversation","scenario":"You've decided to pursue industry after graduation, not the academic path your advisor has been grooming you for. They find out from you now, or from the recruiting-site notification later. The meeting is scheduled.","task":"Write the 2-3 sentence spoken opening that delivers the decision with respect and without apology.","tips":["It's a decision, not a confession: state it as made.","Honor the investment specifically — what their training built that you're taking with you.","What you need from them next (references, intros) comes after the news lands, possibly next meeting."],"focus":["clarity","impact"],"placeholder":"I've decided to go into industry after I defend — and I wanted you to hear it from me first."},
    {"id":"hard-stu-senior-11","level":"senior","profession":"student","title":"The review you must decline","scenario":"An editor invited you to review a manuscript — your first invitation, a real milestone. The manuscript is from a lab you're actively collaborating with, which you're fairly sure the editor doesn't know.","task":"Write the 2-sentence decline that names the conflict and keeps the door open.","tips":["The conflict is the reason — state it plainly; editors respect it.","Offer the future: 'I'd welcome the chance to review for the journal where I'm unconflicted.'","Suggesting an alternative reviewer is a professional courtesy that costs one line."],"focus":["clarity","concision"]},
    {"id":"hard-stu-senior-12","level":"senior","profession":"student","title":"The failing student, told in week eight","scenario":"A student in your section is at 42% with five weeks left. Passing is still mathematically possible but requires immediate change. Your email must be honest enough to trigger action without reading as a verdict already rendered.","task":"Write the 3-sentence email: the number, the trajectory, and the concrete path.","tips":["The number is the kindness — approximations protect you, not them.","Trajectory, not character: 'at this pace' rather than 'you are failing.'","The path must be specific and this-week: office hours Thursday, the resubmission option, the study group."],"focus":["clarity","audience"],"placeholder":"I want to be straight with you: you're at 42%, and passing is still possible if things change this week."},
    {"id":"hard-stu-senior-13","level":"senior","profession":"student","title":"The correction to your published paper","scenario":"A reader's email is right: there's a computational error in Table 2 of your published paper. The main conclusion survives, but the reported effect size is inflated. You need to email the journal editor — a message you'd rather not write and must.","task":"Write the 3-sentence email opening: the error, its scope, and your proposed correction.","tips":["Report it like a scientist: what's wrong, what it affects, what it doesn't.","Propose the correction mechanism — you're bringing a solution, not a confession.","Speed and plainness here build the reputation that matters over decades."],"focus":["precision","clarity"]},
    {"id":"hard-stu-senior-14","level":"senior","profession":"student","title":"The broken instrument you broke","scenario":"You miscalibrated the shared confocal microscope; the lab manager discovered the drift and three other users' sessions may be affected. Reporting yourself now beats being discovered later, by a margin that shrinks hourly.","task":"Write the 2-3 sentence message to the lab manager that owns it completely.","tips":["Own it without qualifiers: what you did, when, which sessions are at risk.","The affected-users list is the urgent part — lead with enabling their damage check.","Offer the repair: recalibration cost, your time, the prevention step."],"focus":["clarity","impact"],"placeholder":"I miscalibrated the confocal on Tuesday — sessions since then may be affected, and here's who should check."},
    {"id":"hard-stu-senior-15","level":"senior","profession":"student","title":"The feedback up the hierarchy","scenario":"Your advisor reschedules your meetings roughly half the time, usually same-day. Your data-collection windows die with each cancellation. The power gap makes this feel unraisable; the cost makes it unskippable.","task":"Write the 2-3 sentence spoken version using behavior, impact, and a workable ask.","tips":["Behavior: 'about half our meetings move same-day.' No motive-reading.","Impact in their currency: the participant sessions and weeks lost.","The ask should be cheap for them: a protected slot, or 24-hour notice."],"focus":["clarity","audience"]},
    {"id":"hard-stu-senior-16","level":"senior","profession":"student","title":"Cutting the co-author's section","scenario":"The journal's revision demands a shorter paper, and the section that must go is the one your co-author contributed — their theoretical framing, which reviewers called 'tangential.' You're first author; the call and the conversation are yours.","task":"Write the 3-sentence message that delivers the cut with its reasoning and an offset.","tips":["The decision first, attributed to the evidence: reviewers and the word limit, not your taste.","Preserve their contribution's future: the framing becomes its own short paper, and you'll say so.","Offer the draft edit for their review — control softens loss."],"focus":["clarity","audience"]},
    {"id":"hard-stu-senior-17","level":"senior","profession":"student","title":"The lab departure announcement","scenario":"You're transferring to a different lab — a better fit for your evolved interests, and everyone will privately understand. The lab meeting announcement still has to happen, with your current PI in the room, after they've already been told privately.","task":"Write the 3-4 sentence spoken announcement that is honest, warm, and unambiguous.","tips":["The fact first, the gratitude second, the logistics third.","Don't perform more regret than you have; rooms detect it.","Name the handoff plan — it's the announcement's professional core."],"focus":["clarity","audience"]},
    {"id":"hard-stu-senior-18","level":"senior","profession":"student","title":"The grade-appeal denial","scenario":"You regraded the student's exam as they requested, carefully. The original grade stands. They're hoping; you're the one who has to end the hoping, in writing, in a way that survives being forwarded to the professor.","task":"Write the 3-sentence email: the outcome, the specific rubric basis, and the closed-but-kind ending.","tips":["Outcome in sentence one — a suspenseful denial is a cruel one.","Cite the rubric line, not your judgment: process protects both of you.","Kind and closed: acknowledge the effort, name the remaining official channel, stop."],"focus":["clarity","precision"]},
    {"id":"hard-stu-senior-19","level":"senior","profession":"student","title":"The conference cancellation","scenario":"A family emergency means you must withdraw from the symposium where you were the third of four speakers — three weeks out. The organizer built the session partly around your dataset. The email needs to land the news and the mitigation in one pass.","task":"Write the 3-sentence email: the withdrawal, the minimum context, and what you can offer instead.","tips":["Withdraw cleanly: the decision is made, not being polled.","Context in one clause — 'a family emergency' is complete.","The offers matter: your slides for the chair, a labmate who could present, a recorded talk."],"focus":["clarity","structure"]},
    {"id":"hard-stu-senior-20","level":"senior","profession":"student","title":"The rotation-student misfit","scenario":"The rotation student you've supervised for eight weeks wants to join the lab. It isn't a fit — their interests need methods your lab doesn't run — and you're the one they'll ask first, tomorrow, hopeful.","task":"Write the 2-3 sentence spoken response that is honest about the fit and generous about the redirect.","tips":["Fit, not worth: the mismatch is between interests and methods, and say exactly that.","Be concrete in the redirect: name the two labs that run those methods.","Don't outsource the no to the PI — they asked you."],"focus":["clarity","audience"],"placeholder":"I don't think this lab is the right fit for what you want to do — and I mean that precisely, so let me explain."},
    {"id":"hard-stu-senior-21","level":"senior","profession":"student","title":"The missed milestone, reported to the funder","scenario":"Your fellowship's annual report is due and the year-two milestone — completed data collection — is at 60%. Funders read hundreds of reports; the ones that hide slippage in prose get flagged, and the ones that report it with a plan get renewed.","task":"Write the 2-3 sentence milestone section that reports the miss with its recovery plan.","tips":["The number first: 60% complete against the year-two target.","One-sentence cause, no cascade.","The plan with dates is what converts a miss into a managed project."],"focus":["precision","clarity"]},
    {"id":"hard-stu-senior-22","level":"senior","profession":"student","title":"The talk that ran long","scenario":"Your labmate's practice job talk ran 62 minutes for a 45-minute slot, and they asked for your honest read. Everyone else said 'great talk!' A real friend does the arithmetic out loud.","task":"Write the 2-3 sentence spoken feedback that names the problem and where the 17 minutes live.","tips":["The number is the feedback: 62 into 45 doesn't go.","Point at the cuts — study two's methods, the literature detour — so it's actionable within the hour.","One genuine strength, briefly, and only if true: it buys nothing if inflated."],"focus":["clarity","precision"]},
    {"id":"hard-stu-senior-23","level":"senior","profession":"student","title":"The mistake found before submission","scenario":"Final checks before submitting the manuscript revealed your preprocessing script excluded the wrong participants — the analysis must be rerun, results may shift, and four co-authors think this submits tonight. The message goes to all of them now.","task":"Write the 3-sentence message: the stop, the cause, and the new timeline.","tips":["'We can't submit tonight' is sentence one — everything else is detail.","The cause, owned, in one sentence: my script, wrong exclusion list.","New timeline with a checkpoint: rerun by Friday, results comparison to all by Monday."],"focus":["clarity","impact"],"placeholder":"We need to hold the submission — I found an error in my preprocessing that requires a rerun."},
    {"id":"hard-stu-senior-24","level":"senior","profession":"student","title":"The 'we can't fund you next term' relay","scenario":"Your PI asked you to tell the junior student you co-supervise that the grant renewal fell through and their RA position ends in December. It's not your decision, but it is now your message — and the student deserves better than a forwarded email.","task":"Write the 2-3 sentence spoken opening that delivers the news directly and separates it from the student's performance.","tips":["News first, source named: the grant fell through; the position ends in December.","Decouple explicitly: this is funding, not performance — say the sentence.","What survives: the reference, the co-authorship, the two months to find the next position together."],"focus":["clarity","audience"]},
    {"id":"hard-stu-senior-25","level":"senior","profession":"student","title":"The self-report before the scoop","scenario":"You presented preliminary data at a workshop; a professor there emailed your advisor questioning whether your analysis double-dipped the selection criteria. They're partially right, and your advisor forwarded it with 'thoughts?' Your reply is the whole ballgame.","task":"Write the 3-sentence reply: where the critique is right, where it isn't, and the fix already underway.","tips":["Concede the true part first and precisely — your advisor is watching how you handle being wrong.","Bound it: which figure is affected, which conclusions stand.","'I've already started the corrected analysis' is the sentence that ends the crisis."],"focus":["precision","impact"],"placeholder":"He's right about the selection step — figure 2 is affected, figures 3-5 are not, and the corrected analysis is already running."}
  ],
  "putting-it-together": [
    {"id":"together-stu-senior-01","level":"senior","profession":"student","title":"The defense-week email suite","scenario":"Defense in three weeks. One email must reach five committee members with the document link, the format, the timing, and the one logistical ask (Professor L joins remotely). Every element you've practiced — lead, structure, concision — gets used or the thread spawns twelve replies.","task":"Write the complete email in under 8 lines.","tips":["Lead with what and when; logistics in a scannable block.","One ask per person maximum, named.","Assume it's read on a phone between meetings."],"focus":["structure","concision"]},
    {"id":"together-stu-senior-02","level":"senior","profession":"student","title":"One result, three registers","scenario":"Your key finding is accepted for publication. Today you need three versions: the abstract's first sentence for specialists, a tweet for academic social media, and two sentences for your parents' inevitable question.","task":"Write all three versions of the same finding.","tips":["Same truth, three altitudes — check that no version overclaims.","The tweet is the hardest: precise AND repeatable.","If the parent version takes longest, that's normal and diagnostic."],"focus":["audience","precision"]},
    {"id":"together-stu-senior-03","level":"senior","profession":"student","title":"The cold email to the postdoc advisor","scenario":"The researcher whose lab you want for your postdoc gets fifty cold emails a semester. Yours has one paragraph to demonstrate fit, signal quality, and make responding easy — every skill in the course, under 120 words.","task":"Write the complete cold email in under 120 words.","tips":["Subject line does half the work: your topic × their lab, specifically.","One sentence proving you know their current work — not their famous work.","The ask should be small and datable: a 20-minute call, these two weeks."],"focus":["audience","concision"],"placeholder":"Subject: Prediction-error work × your reward-learning lab"},
    {"id":"together-stu-senior-04","level":"senior","profession":"student","title":"The full reviewer response","scenario":"Two reviewers, nine comments, one revision deadline. Reviewer 1's major concern requires conceding a limitation; Reviewer 2's central request you must decline with evidence. The response letter is structure, precision, and diplomacy in one document.","task":"Write the response letter's opening paragraph and your response to the comment you're declining.","tips":["Open with the changes made — goodwill before the disagreement.","Decline with evidence and an accommodation: what you added instead.","The editor should be able to rule from your letter alone."],"focus":["structure","precision"]},
    {"id":"together-stu-senior-05","level":"senior","profession":"student","title":"The research statement's first page","scenario":"Academic job applications open in six weeks. The research statement's first half-page decides whether the rest gets read: your question, your contribution, your trajectory — for a committee where nobody shares your subfield.","task":"Write the research statement's opening paragraph (4-5 sentences).","tips":["Governing idea first: the question that organizes everything you do.","One finding, stated with its stake, as proof the question pays.","The trajectory sentence: where this program goes with a lab of your own."],"focus":["structure","impact"]},
    {"id":"together-stu-senior-06","level":"senior","profession":"student","title":"The defense's first two minutes","scenario":"Your defense opens with your statement before questions begin. Two minutes to frame five years: the question, why it mattered, what you found, what it changes. Your committee knows the work — this is about command, not coverage.","task":"Write the complete 2-minute opening statement (roughly 6-8 sentences).","tips":["Open with the question, not the acknowledgments.","One sentence per study; the finding, not the procedure.","Land on the flag-plant: the sentence you want quoted back at the celebration."],"focus":["structure","impact"],"placeholder":"Five years ago I asked a question the field thought was settled."},
    {"id":"together-stu-senior-07","level":"senior","profession":"student","title":"The industry application translation","scenario":"The data scientist posting asks for 'experience with experimentation and causal inference.' Your dissertation is exactly that, in different clothes. The cover letter's first paragraph must complete the translation before a non-academic recruiter stops reading.","task":"Write the cover letter's opening paragraph (3-4 sentences) in industry register.","tips":["Their vocabulary from their posting — mirror 'experimentation,' not 'paradigms.'","Numbers that transfer: dataset sizes, pipelines built, decisions your analyses drove.","Zero academic throat-clearing; recruiters read at scan speed."],"focus":["audience","impact"]},
    {"id":"together-stu-senior-08","level":"senior","profession":"student","title":"The lost-data incident message","scenario":"A server migration ate your lab's shared drive; your backup covers all but nine days of the lab's data — including two labmates' recent sessions. You manage the drive. The lab group message needs the news, the scope, the plan, and the prevention — front-loaded, precise, unpanicked.","task":"Write the complete message in 5-6 lines.","tips":["Headline: what's lost, what's safe — the reader's first question is 'am I affected?'","Named impacts: whose sessions, which dates.","The plan and the prevention each get one line; apology gets one clause."],"focus":["clarity","structure"],"placeholder":"Data status after the server migration: everything is safe except June 3-12 — here's exactly what that means."},
    {"id":"together-stu-senior-09","level":"senior","profession":"student","title":"The timeline negotiation","scenario":"Your advisor wants a fourth study; you want to defend in May with three. This meeting decides it. You need the recommendation owned, the evidence precise, the objection pre-empted, and the message tuned to what your advisor actually optimizes for — your career and the lab's output.","task":"Write your 4-5 sentence spoken opening for the meeting.","tips":["Recommendation first: defend in May with three studies.","Their currency: the fourth study as a post-defense paper keeps the output without the delay.","Pre-empt the rigor worry: the three-study package already answers the committee-approved question."],"focus":["impact","structure"],"placeholder":"I want to make the case for defending in May with three studies — and I think it's better for the lab too."},
    {"id":"together-stu-senior-10","level":"senior","profession":"student","title":"The conference follow-up that converts","scenario":"At the conference, a professor said 'send me that preprint' after your poster. It's the postdoc-pipeline conversation of the year. The follow-up email must reference the moment, deliver the preprint, and advance the relationship — without overreaching.","task":"Write the complete follow-up email in under 100 words.","tips":["Anchor to the specific exchange — their comment about your control condition.","The preprint attached, plus the one-sentence version of what it shows.","One forward step, sized right: not 'hire me,' but 'I'd value your read on the discussion section.'"],"focus":["audience","concision"]},
    {"id":"together-stu-senior-11","level":"senior","profession":"student","title":"The grant aims paragraph","scenario":"Your first grant application as lead. The aims paragraph must state the payoff, the three aims, and their independence-plus-convergence — structure, precision, and stakes in 130 words, for a panel that reads forty of these a day.","task":"Write the complete aims paragraph.","tips":["Payoff sentence first: what the field can do after this grant that it can't now.","Each aim: one sentence, verb-led, with its deliverable.","Read it at panel speed — 30 seconds — and cut what doesn't survive."],"focus":["structure","precision"]},
    {"id":"together-stu-senior-12","level":"senior","profession":"student","title":"The end-of-term TA message","scenario":"Last week of the course you TA'd. One message to 120 students must cover: the final's logistics, the review-session details, what is and isn't examinable, and where to direct panicked questions. Every ambiguity you leave becomes forty identical emails.","task":"Write the complete message in under 10 lines.","tips":["Ruthless structure: bolded labels or numbered blocks, one topic each.","The most-asked question — 'is X on the exam?' — answered explicitly.","Close the loop: where questions go, and when answers stop (the night before)."],"focus":["structure","audience"]},
    {"id":"together-stu-senior-13","level":"senior","profession":"student","title":"The final committee report","scenario":"Your last committee meeting before the defense. The written report must show: milestones hit against last year's commitments, the one deviation with its rationale, and the defense-readiness case. Accountability structure plus owned recommendations plus precise numbers.","task":"Write the report's opening summary paragraph (4-5 sentences).","tips":["Open with the verdict you want them to reach: ready to defend.","Promised-vs-delivered in numbers before anyone asks.","The deviation gets named by you, framed with its reason, before they find it."],"focus":["structure","precision"],"placeholder":"The dissertation is defense-ready: all three studies complete, two published, one under review."},
    {"id":"together-stu-senior-14","level":"senior","profession":"student","title":"The public paper announcement","scenario":"Your paper is out and your LinkedIn post about it will be read by recruiters, academics, and your extended family simultaneously. One post, three audiences: the finding in plain language, its significance without hype, and what you're looking for next — subtly.","task":"Write the complete post in under 120 words.","tips":["The finding in one plain sentence carries all three audiences.","Precision survives hype-detection: one number, one honest boundary.","The trajectory close does the career work: 'next, I'm taking this toward —'"],"focus":["audience","impact"]},
    {"id":"together-stu-senior-15","level":"senior","profession":"student","title":"The urgent request to the grad chair","scenario":"Your funding letter has an error — it lists the wrong end date, and your visa renewal appointment is Thursday. You need a corrected letter in 48 hours from a grad chair who processes requests in order received unless given a reason not to. Lead, precision, stakes: all of it, in one short email.","task":"Write the complete email in under 6 lines.","tips":["Subject line carries the deadline: 'Corrected funding letter needed by Thursday (visa appointment).'","The error, specified: which line, wrong date, right date.","Make fulfillment one action: the corrected draft attached, needing only signature."],"focus":["clarity","precision"],"placeholder":"Subject: Corrected funding letter by Thursday — visa appointment depends on it"},
    {"id":"together-stu-senior-16","level":"senior","profession":"student","title":"The mixed-audience seminar open","scenario":"Your departmental exit seminar draws your committee, first-years, the other field's faculty, and your proud labmates. The first three sentences must give everyone a handle: the specialists a claim, the outsiders a stake, the room a map.","task":"Write the seminar's first three sentences.","tips":["Sentence one: the stake anyone can feel. Sentence two: the claim specialists can grip. Sentence three: the map.","This is audience-calibration under structure — your two hardest skills, stacked.","Rehearse aloud; seminars are heard, not read."],"focus":["audience","structure"]},
    {"id":"together-stu-senior-17","level":"senior","profession":"student","title":"The channel decision","scenario":"You've discovered your co-authored conference submission has an authorship problem: a contributor was left off. Deadline is Friday. Do you raise it by email, Slack, or meeting — and what does the first message say? The channel choice IS part of the message.","task":"Name your channel choice, justify it in one sentence, then write the 2-3 sentence opening message.","tips":["Sensitive plus urgent usually means: short synchronous ask, scheduled by async message.","The written opener should state the issue without adjudicating it — that's for the call.","Time-box it in the message: 'needs 15 minutes before Friday.'"],"focus":["audience","clarity"]},
    {"id":"together-stu-senior-18","level":"senior","profession":"student","title":"The hour talk, cut to five","scenario":"The symposium's schedule collapsed; your 60-minute invited talk is now a 5-minute lightning slot, announced an hour before. This is structural triage: one governing claim, one figure, one implication — chosen, not compressed.","task":"Write the outline of the 5-minute version: the claim, the single figure you keep, and the closing sentence.","tips":["Don't compress — select. Four beats maximum.","The kept figure is the one that proves the claim alone.","Your closing sentence should sell the paper, not summarize the talk."],"focus":["structure","concision"]},
    {"id":"together-stu-senior-19","level":"senior","profession":"student","title":"The write-then-halve exercise","scenario":"Your dissertation's contribution statement — the paragraph your committee, external examiner, and future employers will all read — currently runs 160 words. The discipline: write it fully, then halve it, and watch which claims survive.","task":"Write the 80-word version of your contribution paragraph.","tips":["First pass: cut hedges and meta-commentary. Second: merge overlapping claims.","What survives halving is your actual contribution — the rest was scaffolding.","Every sentence must claim, not narrate."],"focus":["concision","impact"]},
    {"id":"together-stu-senior-20","level":"senior","profession":"student","title":"The register switch","scenario":"Same news — your paper was accepted — needs two messages within the hour: a formal note to your committee (who reviewed drafts) and a Slack message to your lab friends. Getting the registers backwards is the classic graduate-student email accident.","task":"Write both messages: the committee note (2-3 sentences) and the lab Slack (1-2 lines).","tips":["Committee: gratitude with specifics — whose comment improved which section.","Lab: let it be joy; register-matching means informal when informal is true.","Check the failure mode: no exclamation storms in the first, no stiffness in the second."],"focus":["audience","clarity"]},
    {"id":"together-stu-senior-21","level":"senior","profession":"student","title":"The reply-all correction","scenario":"You sent the wrong analysis figures to the entire collaboration mailing list — 30 people, including two PIs who've already replied with comments based on the wrong numbers. The correction must be fast, clean, and must not compound the noise.","task":"Write the complete correction message in 3-4 lines.","tips":["Subject prefix does triage: 'CORRECTION:' — then the same thread.","What was wrong, what's right, what to disregard: one line each.","No apology spiral; one clause, then the fix. Competence is the apology."],"focus":["clarity","concision"],"placeholder":"CORRECTION: the figures in my last email were from the old pipeline — corrected versions attached."},
    {"id":"together-stu-senior-22","level":"senior","profession":"student","title":"The Q&A gauntlet prep","scenario":"Job talk in one week. You know the five questions you fear most — the confound, the small n, the rival theory, the 'why here?', and the one you can't answer. Preparation means writing the answers now, at full pressure-quality, so the room never sees you improvise.","task":"Pick your two hardest questions and write the 2-3 sentence spoken answer to each.","tips":["Each answer: direct response first, evidence second, boundary third.","The unanswerable one gets the honest-with-a-path treatment.","Read them aloud — written answers that can't be spoken aren't answers yet."],"focus":["precision","impact"]},
    {"id":"together-stu-senior-23","level":"senior","profession":"student","title":"The edit-like-a-reader pass","scenario":"Your paper's discussion opens with a 90-word paragraph you've read forty times and can no longer see. The exercise: read it as your busiest committee member would — once, tired, deciding whether to keep reading — then rewrite it for that reader.","task":"Write the rewritten opening paragraph (3-4 sentences) as the tired reader needs it.","tips":["First sentence answers 'so what did all this mean?' — the tired reader's only question.","Each following sentence must earn the next; cut the one that doesn't.","If you can't see the paragraph freshly, read it aloud backwards sentence by sentence."],"focus":["clarity","audience"]},
    {"id":"together-stu-senior-24","level":"senior","profession":"student","title":"The everything-at-stake abstract","scenario":"One conference matters most for your job market year, and its 250-word abstract deadline is tonight. Structure (SCQA in miniature), precision (the real numbers), audience (reviewers outside your subfield), concision (every word costed) — the whole course in 250 words.","task":"Write the complete 250-word abstract for your current research.","tips":["SCQA compressed: situation and complication in two sentences, question in one, your answer as the body.","Numbers where reviewers expect them: n, effect, the key statistic.","Last sentence sells the talk: what the audience leaves with."],"focus":["structure","precision"]},
    {"id":"together-stu-senior-25","level":"senior","profession":"student","title":"The five-years-in-one-page letter","scenario":"Your PhD ends next month. A prospective employer asks for something no template covers: 'a one-page letter telling us what you actually did for five years and why it matters to us.' Not a CV, not a research statement — a letter, in your voice, at full skill.","task":"Write the letter's opening paragraph (4-5 sentences): the arc, the evidence, the relevance.","tips":["The arc first: the question you chased and what the chase built in you.","Evidence at trajectory altitude: not every study — the capability the studies prove.","The relevance turn is the close: their problem, your trained instinct for it.","Voice matters here more than anywhere — formal enough to respect, human enough to remember."],"focus":["impact","audience"]}
  ],
};
